// ── attendance_report_records sync writer (PR2) ──
// 复用既有 per-user export 构建路径; 不重写聚合; 全程经 multitable 插件 API; attendance_* 仍是唯一事实源.
function mapReportFieldToMultitableType(field) {
  const t = field?.formulaEnabled ? field.formulaOutputType : field?.unit
  if (['number', 'duration_minutes', 'count', 'days', 'hours', 'minutes'].includes(t)) return 'number'
  if (t === 'date') return 'date'
  if (t === 'dateTime') return 'dateTime'
  if (t === 'boolean') return 'boolean'
  return 'string'
}

// Stable superset of value columns from the FULL catalog (incl. disabled) so the managed
// column set is deterministic across syncs and disabled fields' columns can be nulled on
// patch (stale-null). Truly-removed-from-catalog codes leave orphan columns = P2 cleanup.
// MUST exclude fixed-skeleton field ids: a catalog code like `work_date` shares the
// logical id of the skeleton column, and since ensureFields is INSERT ON CONFLICT DO
// UPDATE the later (string) value column would overwrite the skeleton type (date). The
// skeleton already carries work_date/employee_name/department/attendance_group values.
function buildAttendanceReportRecordsValueColumns(catalogItems) {
  const skeletonIds = new Set(Object.values(ATTENDANCE_REPORT_RECORDS_FIELDS))
  return (Array.isArray(catalogItems) ? catalogItems : [])
    .filter(field => (
      field
      && field.code
      && !ATTENDANCE_REPORT_FORMULA_RESERVED_CODES.has(field.code)
      && !skeletonIds.has(field.code)
    ))
    .map((field, index) => ({
      id: field.code,
      name: field.name || field.code,
      type: mapReportFieldToMultitableType(field),
      order: 1000 + index,
    }))
}

function attendanceReportRecordRowKey(orgId, userId, workDate) {
  return `${orgId}:${userId}:${workDate}`
}

const ATTENDANCE_REPORT_RECORDS_SYNC_DEFAULT_PAGE_SIZE = 50
const ATTENDANCE_REPORT_RECORDS_SYNC_MAX_PAGE_SIZE = 100

function normalizeAttendanceReportRecordsSyncUserIds(values) {
  const source = Array.isArray(values) ? values : [values]
  const seen = new Set()
  const userIds = []
  for (const value of source) {
    const userId = String(value ?? '').trim()
    if (!userId || seen.has(userId)) continue
    seen.add(userId)
    userIds.push(userId)
  }
  return userIds
}

function normalizeAttendanceReportRecordsSyncPage(rawPage, rawPageSize) {
  const page = Math.max(1, Math.floor(Number(rawPage) || 1))
  const pageSize = Math.min(
    ATTENDANCE_REPORT_RECORDS_SYNC_MAX_PAGE_SIZE,
    Math.max(1, Math.floor(Number(rawPageSize) || ATTENDANCE_REPORT_RECORDS_SYNC_DEFAULT_PAGE_SIZE)),
  )
  return { page, pageSize, offset: (page - 1) * pageSize }
}

async function loadAttendanceReportRecordsSyncUserPage(db, orgId, from, to, options = {}) {
  const { page, pageSize, offset } = normalizeAttendanceReportRecordsSyncPage(options.page, options.pageSize)
  try {
    const countRows = await db.query(
      `SELECT COUNT(*)::int AS total
       FROM user_orgs uo
       JOIN users u ON u.id = uo.user_id
       WHERE uo.org_id = $1
         AND uo.is_active = true
         AND u.is_active = true`,
      [orgId]
    )
    const rows = await db.query(
      `SELECT uo.user_id
       FROM user_orgs uo
       JOIN users u ON u.id = uo.user_id
       WHERE uo.org_id = $1
         AND uo.is_active = true
         AND u.is_active = true
       ORDER BY uo.user_id ASC
       LIMIT $2 OFFSET $3`,
      [orgId, pageSize, offset]
    )
    const totalUsers = Number(countRows[0]?.total ?? rows.length)
    const userIds = normalizeAttendanceReportRecordsSyncUserIds(rows.map(row => row.user_id))
    return {
      userIds,
      totalUsers,
      page,
      pageSize,
      hasNextPage: offset + userIds.length < totalUsers,
      userSelection: 'allUsers',
    }
  } catch (error) {
    if (!isDatabaseSchemaError(error)) throw error
    const countRows = await db.query(
      `SELECT COUNT(*)::int AS total
       FROM (
         SELECT DISTINCT user_id
         FROM attendance_records
         WHERE org_id = $1 AND work_date BETWEEN $2 AND $3
       ) users_with_records`,
      [orgId, from, to]
    )
    const rows = await db.query(
      `SELECT DISTINCT user_id
       FROM attendance_records
       WHERE org_id = $1 AND work_date BETWEEN $2 AND $3
       ORDER BY user_id ASC
       LIMIT $4 OFFSET $5`,
      [orgId, from, to, pageSize, offset]
    )
    const totalUsers = Number(countRows[0]?.total ?? rows.length)
    const userIds = normalizeAttendanceReportRecordsSyncUserIds(rows.map(row => row.user_id))
    return {
      userIds,
      totalUsers,
      page,
      pageSize,
      hasNextPage: offset + userIds.length < totalUsers,
      userSelection: 'attendanceRecordsFallback',
    }
  }
}

function buildAttendanceReportSourceFingerprint(logicalPayload, excluded, extraPayload = {}) {
  const extras = extraPayload && typeof extraPayload === 'object' && !Array.isArray(extraPayload)
    ? Object.keys(extraPayload)
        .sort()
        .map(key => [`__source:${key}`, extraPayload[key]])
    : []
  const canonical = [
    ...Object.keys(logicalPayload)
      .filter(key => !excluded.has(key))
      .sort()
      .map(key => [key, logicalPayload[key]]),
    ...extras,
  ]
  return crypto.createHash('sha1').update(JSON.stringify(canonical)).digest('hex')
}

function buildAttendanceReportRecordSourceFingerprint(logicalPayload, extraPayload = {}) {
  const excluded = new Set([
    ATTENDANCE_REPORT_RECORDS_FIELDS.syncedAt,
    ATTENDANCE_REPORT_RECORDS_FIELDS.fieldFingerprint,
    ATTENDANCE_REPORT_RECORDS_FIELDS.sourceFingerprint,
  ])
  return buildAttendanceReportSourceFingerprint(logicalPayload, excluded, extraPayload)
}

function createAttendanceReportRecordsSyncEmptyResult(extra = {}) {
  return {
    synced: 0,
    rowsSynced: 0,
    patched: 0,
    created: 0,
    skipped: 0,
    failed: 0,
    duplicateRowKeys: 0,
    usersScanned: 0,
    usersSynced: 0,
    usersFailed: 0,
    failedUsers: [],
    ...extra,
  }
}

async function syncAttendanceReportRecords(context, db, orgId, logger, params) {
  const userId = String(params?.userId || '').trim()
  const from = String(params?.from || '').trim()
  const to = String(params?.to || '').trim()
  const empty = { synced: 0, patched: 0, created: 0, skipped: 0, failed: 0, duplicateRowKeys: 0 }

  const ensured = await ensureAttendanceReportRecords(context, orgId, logger)
  if (!ensured.available) {
    return { degraded: true, reason: ensured.reason, ...empty }
  }
  const records = context?.api?.multitable?.records
  const provisioning = context?.api?.multitable?.provisioning
  if (!records?.queryRecords || !records?.createRecord || !records?.patchRecord || !provisioning?.ensureObject) {
    return { degraded: true, reason: 'MULTITABLE_RECORDS_API_UNAVAILABLE', ...empty }
  }

  const formulaOptions = await getAttendanceFormulaRuntimeOptions(db)
  const catalog = await buildAttendanceReportFieldCatalogResponse(context, orgId, logger, {
    provision: false,
    ...formulaOptions,
  })
  const reportFields = await loadAttendanceRecordReportFields(context, orgId, logger, formulaOptions)
  const reportFieldConfig = buildAttendanceReportFieldConfig(reportFields)
  const fieldFingerprint = reportFieldConfig?.fieldsFingerprint?.value || ''

  // ensure value columns (stable superset) via the same ensureObject upsert (idempotent, never deletes)
  const valueColumns = buildAttendanceReportRecordsValueColumns(catalog.items)
  const baseDescriptor = getAttendanceReportRecordsDescriptor()
  await provisioning.ensureObject({
    projectId: ensured.projectId,
    descriptor: { ...baseDescriptor, fields: [...baseDescriptor.fields, ...valueColumns] },
  })
  const logicalIds = [
    ...Object.values(ATTENDANCE_REPORT_RECORDS_FIELDS),
    ...valueColumns.map(column => column.id),
  ]
  const fieldIds = typeof provisioning.resolveFieldIds === 'function'
    ? await provisioning.resolveFieldIds({
      projectId: ensured.projectId,
      objectId: ATTENDANCE_REPORT_RECORDS_OBJECT_ID,
      fieldIds: logicalIds,
    })
    : Object.fromEntries(logicalIds.map(id => [id, id]))
  const physical = logicalId => fieldIds?.[logicalId] || logicalId

  const rows = await db.query(
    `SELECT ar.user_id, ar.org_id, ar.work_date, ar.timezone, ar.first_in_at, ar.last_out_at,
            ar.work_minutes, ar.late_minutes, ar.early_leave_minutes, ar.status, ar.is_workday,
            ar.meta, u.name AS user_name, u.username AS username,
            u.employee_no AS employee_no, u.department AS department,
            u.position AS position, u.hire_date AS hire_date
     FROM attendance_records ar
     LEFT JOIN users u ON u.id = ar.user_id
     WHERE ar.user_id = $1 AND ar.org_id = $2 AND ar.work_date BETWEEN $3 AND $4
     ORDER BY ar.work_date DESC
     LIMIT 5000`,
    [userId, orgId, from, to]
  )
  const approvedMap = await loadApprovedMinutesRange(db, orgId, userId, from, to)

  const result = { ...empty, synced: rows.length }
  const syncedAt = new Date().toISOString()
  for (const row of rows) {
    try {
      const workDate = normalizeDateOnly(row.work_date) ?? String(row.work_date ?? '').slice(0, 10)
      const approved = approvedMap.get(workDate) ?? { leaveMinutes: 0, overtimeMinutes: 0, reportSubtypeMinutes: {} }
      const enrichedRow = {
        ...row,
        work_date: workDate,
        meta: {
          ...normalizeMetadata(row.meta),
          leave_minutes: approved.leaveMinutes,
          overtime_minutes: approved.overtimeMinutes,
          ...buildApprovedOvertimeSegmentationMeta(approved),
          reportSubtypeMinutes: approved.reportSubtypeMinutes ?? {},
        },
      }
      const exportItem = await buildAttendanceRecordReportExportItemAsync(
        context,
        enrichedRow,
        reportFields.fields,
        reportFields.formulaSourceFields,
        formulaOptions,
      )
      const rowKey = attendanceReportRecordRowKey(orgId, userId, workDate)
      const logical = {
        [ATTENDANCE_REPORT_RECORDS_FIELDS.rowKey]: rowKey,
        [ATTENDANCE_REPORT_RECORDS_FIELDS.orgId]: orgId,
        [ATTENDANCE_REPORT_RECORDS_FIELDS.userId]: userId,
        [ATTENDANCE_REPORT_RECORDS_FIELDS.employeeName]: firstNonEmptyValue(row.user_name, row.username, userId),
        [ATTENDANCE_REPORT_RECORDS_FIELDS.department]: getAttendanceRecordReportFieldValue(enrichedRow, 'department'),
        [ATTENDANCE_REPORT_RECORDS_FIELDS.attendanceGroup]: firstNonEmptyValue(readAttendanceRecordMeta(enrichedRow, ['attendanceGroup', 'attendance_group', '考勤组'])),
        [ATTENDANCE_REPORT_RECORDS_FIELDS.workDate]: workDate,
      }
      for (const column of valueColumns) {
        // active output → value; managed but not active (disabled etc.) → null (stale clear)
        logical[column.id] = Object.prototype.hasOwnProperty.call(exportItem, column.id)
          ? exportItem[column.id]
          : null
      }
      const sourceFingerprint = buildAttendanceReportRecordSourceFingerprint(logical, {
        overtimeSegmentation: buildAttendanceRecordOvertimeSegmentationFingerprintInput(enrichedRow),
      })

      const data = {}
      for (const [logicalId, value] of Object.entries(logical)) {
        data[physical(logicalId)] = value
      }
      data[physical(ATTENDANCE_REPORT_RECORDS_FIELDS.fieldFingerprint)] = fieldFingerprint
      data[physical(ATTENDANCE_REPORT_RECORDS_FIELDS.sourceFingerprint)] = sourceFingerprint
      data[physical(ATTENDANCE_REPORT_RECORDS_FIELDS.syncedAt)] = syncedAt

      const existing = await records.queryRecords({
        sheetId: ensured.sheetId,
        filters: { [physical(ATTENDANCE_REPORT_RECORDS_FIELDS.rowKey)]: rowKey },
        limit: 50,
      })
      if (!Array.isArray(existing) || existing.length === 0) {
        await records.createRecord({ sheetId: ensured.sheetId, data })
        result.created += 1
        continue
      }
      if (existing.length > 1) result.duplicateRowKeys += existing.length - 1
      const target = existing[0]
      const existingData = (target && target.data && typeof target.data === 'object') ? target.data : {}
      const existingSource = existingData[physical(ATTENDANCE_REPORT_RECORDS_FIELDS.sourceFingerprint)]
      const existingField = existingData[physical(ATTENDANCE_REPORT_RECORDS_FIELDS.fieldFingerprint)]
      if (existingSource === sourceFingerprint && existingField === fieldFingerprint) {
        result.skipped += 1
        continue
      }
      await records.patchRecord({ sheetId: ensured.sheetId, recordId: target.id, changes: data })
      result.patched += 1
    } catch (error) {
      result.failed += 1
      logger?.warn?.('attendance report record sync row failed', {
        error: error instanceof Error ? error.message : String(error),
      })
    }
  }
  return {
    ...result,
    rowsSynced: result.synced,
    fieldFingerprint,
    syncedAt,
    multitable: {
      available: true,
      degraded: false,
      projectId: ensured.projectId,
      objectId: ensured.objectId,
      baseId: ensured.baseId || null,
      sheetId: ensured.sheetId || null,
      viewId: ensured.viewId || null,
    },
  }
}

async function syncAttendanceReportRecordsForUsers(context, db, orgId, logger, params) {
  const from = String(params?.from || '').trim()
  const to = String(params?.to || '').trim()
  const explicitUserIds = normalizeAttendanceReportRecordsSyncUserIds(params?.userIds)
  const selection = explicitUserIds.length > 0
    ? {
        userIds: explicitUserIds,
        totalUsers: explicitUserIds.length,
        page: 1,
        pageSize: explicitUserIds.length,
        hasNextPage: false,
        userSelection: 'explicit',
      }
    : await loadAttendanceReportRecordsSyncUserPage(db, orgId, from, to, {
      page: params?.page,
      pageSize: params?.pageSize,
    })

  const aggregate = createAttendanceReportRecordsSyncEmptyResult({
    totalUsers: selection.totalUsers,
    page: selection.page,
    pageSize: selection.pageSize,
    hasNextPage: selection.hasNextPage,
    userSelection: selection.userSelection,
  })

  for (const userId of selection.userIds) {
    aggregate.usersScanned += 1
    try {
      const result = await syncAttendanceReportRecords(context, db, orgId, logger, { from, to, userId })
      if (result.degraded) {
        return {
          ...aggregate,
          ...result,
          rowsSynced: aggregate.synced,
          totalUsers: selection.totalUsers,
          page: selection.page,
          pageSize: selection.pageSize,
          hasNextPage: selection.hasNextPage,
          userSelection: selection.userSelection,
        }
      }
      aggregate.usersSynced += 1
      aggregate.synced += Number(result.synced ?? 0)
      aggregate.rowsSynced = aggregate.synced
      aggregate.created += Number(result.created ?? 0)
      aggregate.patched += Number(result.patched ?? 0)
      aggregate.skipped += Number(result.skipped ?? 0)
      aggregate.failed += Number(result.failed ?? 0)
      aggregate.duplicateRowKeys += Number(result.duplicateRowKeys ?? 0)
      if (Number(result.failed ?? 0) > 0) {
        aggregate.failedUsers.push({ userId, failedRows: Number(result.failed ?? 0) })
      }
      if (result.fieldFingerprint) aggregate.fieldFingerprint = result.fieldFingerprint
      if (result.syncedAt) aggregate.syncedAt = result.syncedAt
      if (result.multitable) aggregate.multitable = result.multitable
    } catch (error) {
      aggregate.usersFailed += 1
      aggregate.failed += 1
      aggregate.failedUsers.push({
        userId,
        error: error instanceof Error ? error.message : String(error),
      })
      logger?.warn?.('attendance report records user sync failed', {
        userId,
        error: error instanceof Error ? error.message : String(error),
      })
    }
  }
  aggregate.usersFailed = aggregate.failedUsers.length
  return aggregate
}

// ── attendance report sync job control plane (PR1: schema + helper skeleton only) ──
// The job row is operational cursor/progress state. It never becomes a report
// fact source; PR2 runner must delegate page work to the existing daily/period
// sync writers above instead of duplicating statistics or multitable upsert logic.
const ATTENDANCE_REPORT_SYNC_JOB_TABLE = 'plugin_attendance_report_sync_jobs'
const ATTENDANCE_REPORT_SYNC_JOB_KINDS = Object.freeze(['daily_records', 'period_summaries'])
const ATTENDANCE_REPORT_SYNC_JOB_STATUSES = Object.freeze(['queued', 'running', 'paused', 'completed', 'failed', 'canceled'])
const ATTENDANCE_REPORT_SYNC_JOB_MODES = Object.freeze(['manual_step', 'enqueue'])

function createAttendanceReportSyncJobValidationError(message, code = 'VALIDATION_ERROR') {
  return { ok: false, status: 400, code, message }
}

function normalizeAttendanceReportSyncJobKind(value) {
  const kind = normalizeCatalogString(value)
  return ATTENDANCE_REPORT_SYNC_JOB_KINDS.includes(kind) ? kind : null
}

function normalizeAttendanceReportSyncJobStatus(value) {
  const status = normalizeCatalogString(value, 'queued')
  return ATTENDANCE_REPORT_SYNC_JOB_STATUSES.includes(status) ? status : 'queued'
}

function normalizeAttendanceReportSyncJobMode(value) {
  const mode = normalizeCatalogString(value, 'manual_step')
  return ATTENDANCE_REPORT_SYNC_JOB_MODES.includes(mode) ? mode : null
}

function normalizeAttendanceReportSyncJobPeriodSource(value = {}) {
  const source = normalizeMetadata(value)
  const cycleIdInput = normalizeCatalogString(source.cycleId)
  const hasCycleId = Boolean(cycleIdInput)
  const hasFrom = source.from !== undefined && normalizeCatalogString(source.from) !== ''
  const hasTo = source.to !== undefined && normalizeCatalogString(source.to) !== ''
  if (hasCycleId && (hasFrom || hasTo)) {
    return createAttendanceReportSyncJobValidationError('Use either cycleId or from/to, not both')
  }
  if (hasCycleId) {
    const cycleId = normalizeUuidString(cycleIdInput)
    if (!cycleId) {
      return createAttendanceReportSyncJobValidationError('Invalid cycleId')
    }
    return { ok: true, value: { cycleId }, periodType: 'payroll_cycle' }
  }
  if (!hasFrom && !hasTo) {
    return createAttendanceReportSyncJobValidationError('periodSource.cycleId or periodSource.from/to is required')
  }
  if (!hasFrom || !hasTo) {
    return createAttendanceReportSyncJobValidationError('Both periodSource.from and periodSource.to are required')
  }
  const dateRange = resolveAttendanceDateRange(source.from, source.to)
  if (!dateRange.ok) {
    return createAttendanceReportSyncJobValidationError(dateRange.message)
  }
  return {
    ok: true,
    value: { from: dateRange.from, to: dateRange.to },
    periodType: 'date_range',
  }
}

function normalizeAttendanceReportSyncJobUserSelection(value = {}) {
  const source = normalizeMetadata(value)
  const allUsers = source.allUsers === true || String(source.allUsers ?? '').trim().toLowerCase() === 'true'
  const userId = normalizeCatalogString(source.userId)
  const userIds = normalizeAttendanceReportRecordsSyncUserIds(source.userIds)
  const selectedCount = (allUsers ? 1 : 0) + (userId ? 1 : 0) + (userIds.length > 0 ? 1 : 0)
  if (selectedCount !== 1) {
    return createAttendanceReportSyncJobValidationError('Choose exactly one of userId, userIds, or allUsers')
  }
  if (allUsers) return { ok: true, value: { allUsers: true }, selectionType: 'allUsers' }
  if (userId) return { ok: true, value: { userId }, selectionType: 'userId' }
  return { ok: true, value: { userIds }, selectionType: 'userIds' }
}

function createAttendanceReportSyncJobEmptyTotals() {
  return {
    usersScanned: 0,
    usersSynced: 0,
    usersFailed: 0,
    synced: 0,
    rowsSynced: 0,
    created: 0,
    patched: 0,
    skipped: 0,
    failed: 0,
    duplicateRowKeys: 0,
  }
}

function createAttendanceReportSyncJobInitialCursor(pageSize) {
  const normalized = normalizeAttendanceReportRecordsSyncPage(1, pageSize)
  return {
    nextPage: 1,
    pageSize: normalized.pageSize,
    hasNextPage: true,
  }
}

function normalizeAttendanceReportSyncJobCreateInput(input = {}) {
  const raw = normalizeMetadata(input)
  const kind = normalizeAttendanceReportSyncJobKind(raw.kind)
  if (!kind) {
    return createAttendanceReportSyncJobValidationError('kind must be daily_records or period_summaries')
  }
  const periodSource = normalizeAttendanceReportSyncJobPeriodSource(raw.periodSource ?? raw)
  if (!periodSource.ok) return periodSource
  const userSelection = normalizeAttendanceReportSyncJobUserSelection(raw.userSelection ?? raw)
  if (!userSelection.ok) return userSelection
  const mode = normalizeAttendanceReportSyncJobMode(raw.mode)
  if (!mode) {
    return createAttendanceReportSyncJobValidationError('mode must be manual_step or enqueue')
  }
  const page = normalizeAttendanceReportRecordsSyncPage(1, raw.pageSize)
  const idempotencyKey = normalizeCatalogString(raw.idempotencyKey)
  return {
    ok: true,
    value: {
      kind,
      mode,
      periodSource: periodSource.value,
      periodType: periodSource.periodType,
      userSelection: userSelection.value,
      selectionType: userSelection.selectionType,
      cursor: createAttendanceReportSyncJobInitialCursor(page.pageSize),
      totals: createAttendanceReportSyncJobEmptyTotals(),
      idempotencyKey: idempotencyKey || null,
    },
  }
}

function buildAttendanceReportSyncJobInsertRow(orgId, createdBy, input = {}) {
  const parsed = normalizeAttendanceReportSyncJobCreateInput(input)
  if (!parsed.ok) return parsed
  const createdByText = normalizeCatalogString(createdBy)
  return {
    ok: true,
    value: {
      orgId: normalizeAttendanceReportFieldOrgId(orgId),
      kind: parsed.value.kind,
      status: 'queued',
      createdBy: createdByText || null,
      periodSource: parsed.value.periodSource,
      userSelection: parsed.value.userSelection,
      cursor: parsed.value.cursor,
      totals: parsed.value.totals,
      lastResult: {},
      error: null,
      idempotencyKey: parsed.value.idempotencyKey,
      mode: parsed.value.mode,
      periodType: parsed.value.periodType,
      selectionType: parsed.value.selectionType,
    },
  }
}

function normalizeAttendanceReportSyncJobJson(value, fallback = {}) {
  const normalized = normalizeMetadata(value)
  return Object.keys(normalized).length > 0 ? normalized : fallback
}

function normalizeAttendanceReportSyncJobTimestamp(value) {
  if (!value) return null
  if (value instanceof Date) return value.toISOString()
  const text = String(value)
  const date = new Date(text)
  return Number.isNaN(date.getTime()) ? text : date.toISOString()
}

function mapAttendanceReportSyncJobRow(row = {}) {
  if (!row || typeof row !== 'object') return null
  return {
    id: row.id ? String(row.id) : null,
    orgId: normalizeAttendanceReportFieldOrgId(row.org_id),
    kind: normalizeAttendanceReportSyncJobKind(row.kind) || 'daily_records',
    status: normalizeAttendanceReportSyncJobStatus(row.status),
    mode: normalizeAttendanceReportSyncJobMode(row.mode) || 'manual_step',
    createdBy: normalizeCatalogString(row.created_by) || null,
    periodSource: normalizeAttendanceReportSyncJobJson(row.period_source),
    userSelection: normalizeAttendanceReportSyncJobJson(row.user_selection),
    cursor: normalizeAttendanceReportSyncJobJson(row.cursor, createAttendanceReportSyncJobInitialCursor()),
    totals: {
      ...createAttendanceReportSyncJobEmptyTotals(),
      ...normalizeAttendanceReportSyncJobJson(row.totals),
    },
    lastResult: normalizeAttendanceReportSyncJobJson(row.last_result),
    error: row.error == null ? null : String(row.error),
    idempotencyKey: normalizeCatalogString(row.idempotency_key) || null,
    lockedAt: normalizeAttendanceReportSyncJobTimestamp(row.locked_at),
    startedAt: normalizeAttendanceReportSyncJobTimestamp(row.started_at),
    finishedAt: normalizeAttendanceReportSyncJobTimestamp(row.finished_at),
    createdAt: normalizeAttendanceReportSyncJobTimestamp(row.created_at),
    updatedAt: normalizeAttendanceReportSyncJobTimestamp(row.updated_at),
  }
}

async function createAttendanceReportSyncJob(db, orgId, createdBy, input = {}) {
  const built = buildAttendanceReportSyncJobInsertRow(orgId, createdBy, input)
  if (!built.ok) return built
  const row = built.value
  const rows = await db.query(
    `INSERT INTO ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
      (org_id, kind, status, mode, created_by, period_source, user_selection, cursor, totals, last_result, error, idempotency_key)
     VALUES ($1, $2, $3, $4, $5, $6::jsonb, $7::jsonb, $8::jsonb, $9::jsonb, $10::jsonb, $11, $12)
     RETURNING *`,
    [
      row.orgId,
      row.kind,
      row.status,
      row.mode,
      row.createdBy,
      JSON.stringify(row.periodSource),
      JSON.stringify(row.userSelection),
      JSON.stringify(row.cursor),
      JSON.stringify(row.totals),
      JSON.stringify(row.lastResult),
      row.error,
      row.idempotencyKey,
    ],
  )
  return { ok: true, status: 201, job: mapAttendanceReportSyncJobRow(rows[0]) }
}

async function loadAttendanceReportSyncJob(db, orgId, jobId) {
  const id = normalizeUuidString(jobId)
  if (!id) {
    return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: 'Invalid job id' }
  }
  const rows = await db.query(
    `SELECT * FROM ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
     WHERE id = $1 AND org_id = $2
     LIMIT 1`,
    [id, normalizeAttendanceReportFieldOrgId(orgId)],
  )
  if (!rows.length) {
    return { ok: false, status: 404, code: 'NOT_FOUND', message: 'Attendance report sync job not found' }
  }
  return { ok: true, job: mapAttendanceReportSyncJobRow(rows[0]) }
}

const ATTENDANCE_REPORT_SYNC_JOB_LOCK_TTL_MS = 10 * 60 * 1000
const ATTENDANCE_REPORT_SYNC_JOB_LIST_DEFAULT_LIMIT = 50
const ATTENDANCE_REPORT_SYNC_JOB_LIST_MAX_LIMIT = 100
const ATTENDANCE_REPORT_SYNC_JOB_TERMINAL_STATUSES = new Set(['completed', 'canceled'])
const ATTENDANCE_REPORT_SYNC_JOB_TOTAL_KEYS = Object.freeze([
  'usersScanned',
  'usersSynced',
  'usersFailed',
  'synced',
  'rowsSynced',
  'created',
  'patched',
  'skipped',
  'failed',
  'duplicateRowKeys',
])

function isAttendanceReportSyncJobTerminalStatus(status) {
  return ATTENDANCE_REPORT_SYNC_JOB_TERMINAL_STATUSES.has(normalizeAttendanceReportSyncJobStatus(status))
}

function isAttendanceReportSyncJobFreshlyLocked(job, now = new Date()) {
  if (!job || normalizeAttendanceReportSyncJobStatus(job.status) !== 'running' || !job.lockedAt) return false
  const lockedAtMs = new Date(job.lockedAt).getTime()
  const nowMs = now instanceof Date ? now.getTime() : new Date(now).getTime()
  if (!Number.isFinite(lockedAtMs) || !Number.isFinite(nowMs)) return false
  return nowMs - lockedAtMs < ATTENDANCE_REPORT_SYNC_JOB_LOCK_TTL_MS
}

function normalizeAttendanceReportSyncJobLimit(value) {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return ATTENDANCE_REPORT_SYNC_JOB_LIST_DEFAULT_LIMIT
  return Math.min(Math.max(Math.floor(parsed), 1), ATTENDANCE_REPORT_SYNC_JOB_LIST_MAX_LIMIT)
}

function normalizeAttendanceReportSyncJobTotalNumber(value) {
  const parsed = Number(value)
  return Number.isFinite(parsed) && parsed > 0 ? parsed : 0
}

function mergeAttendanceReportSyncJobTotals(existingTotals = {}, pageResult = {}) {
  const merged = {
    ...createAttendanceReportSyncJobEmptyTotals(),
    ...normalizeAttendanceReportSyncJobJson(existingTotals),
  }
  for (const key of ATTENDANCE_REPORT_SYNC_JOB_TOTAL_KEYS) {
    merged[key] = normalizeAttendanceReportSyncJobTotalNumber(merged[key])
      + normalizeAttendanceReportSyncJobTotalNumber(pageResult[key])
  }
  merged.rowsSynced = merged.synced
  const failedUsers = [
    ...(Array.isArray(merged.failedUsers) ? merged.failedUsers : []),
    ...(Array.isArray(pageResult.failedUsers) ? pageResult.failedUsers : []),
  ].slice(0, 50)
  if (failedUsers.length > 0) merged.failedUsers = failedUsers
  return merged
}

function sanitizeAttendanceReportSyncJobLastResult(pageResult = {}) {
  const allowedKeys = [
    'periodType',
    'periodKey',
    'cycleId',
    'from',
    'to',
    'totalUsers',
    'page',
    'pageSize',
    'hasNextPage',
    'usersScanned',
    'usersSynced',
    'usersFailed',
    'synced',
    'rowsSynced',
    'created',
    'patched',
    'skipped',
    'failed',
    'duplicateRowKeys',
    'fieldFingerprint',
    'syncedAt',
    'reason',
    'degraded',
  ]
  const output = {}
  for (const key of allowedKeys) {
    if (pageResult[key] !== undefined) output[key] = pageResult[key]
  }
  if (Array.isArray(pageResult.failedUsers) && pageResult.failedUsers.length > 0) {
    output.failedUsers = pageResult.failedUsers.slice(0, 20)
  }
  if (pageResult.multitable && typeof pageResult.multitable === 'object') {
    output.multitable = {
      available: pageResult.multitable.available,
      projectId: pageResult.multitable.projectId,
      sheetId: pageResult.multitable.sheetId,
      viewId: pageResult.multitable.viewId,
    }
  }
  return output
}

function isAttendanceReportSyncJobExplicitUserSelection(job) {
  const selection = normalizeMetadata(job?.userSelection)
  if (normalizeCatalogString(selection.userId)) return true
  return Array.isArray(selection.userIds) && normalizeAttendanceReportRecordsSyncUserIds(selection.userIds).length > 0
}

function buildAttendanceReportSyncJobUserParams(job) {
  const selection = normalizeMetadata(job?.userSelection)
  if (normalizeCatalogString(selection.userId)) {
    return { userIds: [normalizeCatalogString(selection.userId)] }
  }
  const userIds = normalizeAttendanceReportRecordsSyncUserIds(selection.userIds)
  if (userIds.length > 0) return { userIds }
  const cursor = normalizeAttendanceReportSyncJobJson(job?.cursor, createAttendanceReportSyncJobInitialCursor())
  const page = normalizeAttendanceReportRecordsSyncPage(cursor.nextPage, cursor.pageSize)
  return {
    allUsers: true,
    page: page.page,
    pageSize: page.pageSize,
  }
}

async function listAttendanceReportSyncJobs(db, orgId, filters = {}) {
  const clauses = ['org_id = $1']
  const params = [normalizeAttendanceReportFieldOrgId(orgId)]
  const rawKind = normalizeCatalogString(filters.kind)
  const kind = normalizeAttendanceReportSyncJobKind(rawKind)
  if (rawKind && !kind) {
    return createAttendanceReportSyncJobValidationError('Invalid job kind')
  }
  if (kind) {
    params.push(kind)
    clauses.push(`kind = $${params.length}`)
  }
  const rawStatus = normalizeCatalogString(filters.status)
  if (rawStatus) {
    const status = normalizeAttendanceReportSyncJobStatus(rawStatus)
    if (!ATTENDANCE_REPORT_SYNC_JOB_STATUSES.includes(rawStatus)) {
      return createAttendanceReportSyncJobValidationError('Invalid job status')
    }
    params.push(status)
    clauses.push(`status = $${params.length}`)
  }
  params.push(normalizeAttendanceReportSyncJobLimit(filters.limit))
  const rows = await db.query(
    `SELECT * FROM ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
     WHERE ${clauses.join(' AND ')}
     ORDER BY created_at DESC, id DESC
     LIMIT $${params.length}`,
    params,
  )
  return { ok: true, jobs: rows.map(mapAttendanceReportSyncJobRow).filter(Boolean) }
}

async function lockAttendanceReportSyncJobForRun(db, orgId, jobId, now = new Date()) {
  const id = normalizeUuidString(jobId)
  if (!id) return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: 'Invalid job id' }
  const lockedAt = now instanceof Date ? now : new Date(now)
  const staleBefore = new Date(lockedAt.getTime() - ATTENDANCE_REPORT_SYNC_JOB_LOCK_TTL_MS)
  const rows = await db.query(
    `UPDATE ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
     SET status = 'running',
         locked_at = $3::timestamptz,
         started_at = COALESCE(started_at, $3::timestamptz),
         updated_at = $3::timestamptz
     WHERE id = $1
       AND org_id = $2
       AND status NOT IN ('completed', 'canceled')
       AND (status <> 'running' OR locked_at IS NULL OR locked_at < $4::timestamptz)
     RETURNING *`,
    [id, normalizeAttendanceReportFieldOrgId(orgId), lockedAt.toISOString(), staleBefore.toISOString()],
  )
  if (rows.length > 0) {
    return { ok: true, job: mapAttendanceReportSyncJobRow(rows[0]) }
  }
  const existing = await loadAttendanceReportSyncJob(db, orgId, id)
  if (!existing.ok) return existing
  if (isAttendanceReportSyncJobTerminalStatus(existing.job.status)) {
    return { ok: false, status: 409, code: 'JOB_TERMINAL', message: 'Completed or canceled attendance report sync jobs cannot run again' }
  }
  if (isAttendanceReportSyncJobFreshlyLocked(existing.job, lockedAt)) {
    return { ok: false, status: 409, code: 'JOB_LOCKED', message: 'Attendance report sync job is already running' }
  }
  return { ok: false, status: 409, code: 'JOB_CONFLICT', message: 'Attendance report sync job cannot be locked for running' }
}

async function persistAttendanceReportSyncJobPageState(db, orgId, jobId, state = {}, now = new Date()) {
  const id = normalizeUuidString(jobId)
  if (!id) return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: 'Invalid job id' }
  const status = normalizeAttendanceReportSyncJobStatus(state.status)
  const finishedAt = isAttendanceReportSyncJobTerminalStatus(status) ? now.toISOString() : null
  const rows = await db.query(
    `UPDATE ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
     SET status = $3,
         cursor = $4::jsonb,
         totals = $5::jsonb,
         last_result = $6::jsonb,
         error = $7,
         locked_at = NULL,
         finished_at = COALESCE($8::timestamptz, finished_at),
         updated_at = $9::timestamptz
     WHERE id = $1 AND org_id = $2
     RETURNING *`,
    [
      id,
      normalizeAttendanceReportFieldOrgId(orgId),
      status,
      JSON.stringify(state.cursor ?? createAttendanceReportSyncJobInitialCursor()),
      JSON.stringify(state.totals ?? createAttendanceReportSyncJobEmptyTotals()),
      JSON.stringify(state.lastResult ?? {}),
      state.error ?? null,
      finishedAt,
      now.toISOString(),
    ],
  )
  if (!rows.length) {
    return { ok: false, status: 404, code: 'NOT_FOUND', message: 'Attendance report sync job not found' }
  }
  return { ok: true, job: mapAttendanceReportSyncJobRow(rows[0]) }
}

async function resolveAttendanceReportSyncJobDateRange(db, orgId, job, options = {}) {
  const periodSource = normalizeMetadata(job?.periodSource)
  if (periodSource.cycleId) {
    const resolver = options.resolvePeriod || resolveAttendanceReportPeriodSyncPeriod
    const resolved = await resolver(db, orgId, periodSource)
    if (!resolved.ok) return resolved
    return { ok: true, from: resolved.period.from, to: resolved.period.to, period: resolved.period }
  }
  const dateRange = resolveAttendanceDateRange(periodSource.from, periodSource.to)
  if (!dateRange.ok) {
    return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: dateRange.message }
  }
  return { ok: true, from: dateRange.from, to: dateRange.to }
}

async function executeAttendanceReportSyncJobPage(context, db, orgId, logger, job, options = {}) {
  const userParams = buildAttendanceReportSyncJobUserParams(job)
  if (job.kind === 'daily_records') {
    const dateRange = await resolveAttendanceReportSyncJobDateRange(db, orgId, job, options)
    if (!dateRange.ok) return dateRange
    const writer = options.dailyWriter || syncAttendanceReportRecordsForUsers
    return {
      ok: true,
      result: await writer(context, db, orgId, logger, {
        from: dateRange.from,
        to: dateRange.to,
        ...userParams,
      }),
    }
  }
  if (job.kind === 'period_summaries') {
    const resolver = options.resolvePeriod || resolveAttendanceReportPeriodSyncPeriod
    const resolvedPeriod = await resolver(db, orgId, job.periodSource)
    if (!resolvedPeriod.ok) return resolvedPeriod
    const writer = options.periodWriter || syncAttendanceReportPeriodSummariesForUsers
    return {
      ok: true,
      result: await writer(context, db, orgId, logger, {
        period: resolvedPeriod.period,
        ...userParams,
      }),
    }
  }
  return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: 'Unsupported report sync job kind' }
}

function buildAttendanceReportSyncJobCursorAfterPage(job, pageResult = {}, completed = false) {
  const current = normalizeAttendanceReportSyncJobJson(job?.cursor, createAttendanceReportSyncJobInitialCursor())
  const page = normalizeAttendanceReportRecordsSyncPage(current.nextPage, current.pageSize)
  const hasNextPage = completed ? false : pageResult.hasNextPage === true
  return {
    ...current,
    nextPage: hasNextPage ? page.page + 1 : page.page,
    pageSize: page.pageSize,
    hasNextPage,
  }
}

async function runAttendanceReportSyncJobNextPage(context, db, orgId, logger, jobId, options = {}) {
  const now = options.now instanceof Date ? options.now : new Date()
  const locked = await lockAttendanceReportSyncJobForRun(db, orgId, jobId, now)
  if (!locked.ok) return locked
  const job = locked.job
  try {
    const page = await executeAttendanceReportSyncJobPage(context, db, orgId, logger, job, options)
    if (!page.ok) {
      const failed = await persistAttendanceReportSyncJobPageState(db, orgId, job.id, {
        status: 'failed',
        cursor: job.cursor,
        totals: job.totals,
        lastResult: { error: page.message, code: page.code },
        error: page.message || 'Failed to run attendance report sync job page',
      }, now)
      return { ok: true, job: failed.job, pageResult: { error: page.message, code: page.code } }
    }
    const pageResult = page.result || {}
    if (pageResult.degraded) {
      const failed = await persistAttendanceReportSyncJobPageState(db, orgId, job.id, {
        status: 'failed',
        cursor: job.cursor,
        totals: job.totals,
        lastResult: sanitizeAttendanceReportSyncJobLastResult(pageResult),
        error: pageResult.reason || 'DEGRADED',
      }, now)
      return { ok: true, job: failed.job, pageResult }
    }
    const totals = mergeAttendanceReportSyncJobTotals(job.totals, pageResult)
    const explicitUsers = isAttendanceReportSyncJobExplicitUserSelection(job)
    const allRowsFailed = normalizeAttendanceReportSyncJobTotalNumber(pageResult.usersScanned) > 0
      && normalizeAttendanceReportSyncJobTotalNumber(pageResult.usersFailed) >= normalizeAttendanceReportSyncJobTotalNumber(pageResult.usersScanned)
    const completed = explicitUsers || pageResult.hasNextPage !== true
    const status = allRowsFailed ? 'failed' : (completed ? 'completed' : 'queued')
    const cursor = buildAttendanceReportSyncJobCursorAfterPage(job, pageResult, completed || allRowsFailed)
    const saved = await persistAttendanceReportSyncJobPageState(db, orgId, job.id, {
      status,
      cursor,
      totals,
      lastResult: sanitizeAttendanceReportSyncJobLastResult(pageResult),
      error: allRowsFailed ? 'All users in the page failed' : null,
    }, now)
    return { ok: true, job: saved.job, pageResult }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    logger?.warn?.('attendance report sync job page failed', { jobId: job.id, error: message })
    const failed = await persistAttendanceReportSyncJobPageState(db, orgId, job.id, {
      status: 'failed',
      cursor: job.cursor,
      totals: job.totals,
      lastResult: { error: message },
      error: message,
    }, now)
    return { ok: true, job: failed.job, pageResult: { error: message } }
  }
}

async function cancelAttendanceReportSyncJob(db, orgId, jobId, now = new Date()) {
  const loaded = await loadAttendanceReportSyncJob(db, orgId, jobId)
  if (!loaded.ok) return loaded
  if (isAttendanceReportSyncJobTerminalStatus(loaded.job.status)) {
    return { ok: false, status: 409, code: 'JOB_TERMINAL', message: 'Completed or canceled attendance report sync jobs cannot be canceled again' }
  }
  const rows = await db.query(
    `UPDATE ${ATTENDANCE_REPORT_SYNC_JOB_TABLE}
     SET status = 'canceled',
         locked_at = NULL,
         finished_at = $3::timestamptz,
         updated_at = $3::timestamptz
     WHERE id = $1 AND org_id = $2
     RETURNING *`,
    [loaded.job.id, normalizeAttendanceReportFieldOrgId(orgId), now.toISOString()],
  )
  if (!rows.length) {
    return { ok: false, status: 404, code: 'NOT_FOUND', message: 'Attendance report sync job not found' }
  }
  return { ok: true, job: mapAttendanceReportSyncJobRow(rows[0]) }
}

function resolveAttendanceReportPeriodSummaryManagedFormulaFields(items) {
  return (Array.isArray(items) ? items : [])
    .filter(field => (
      field
      && field.code
      && field.formulaEnabled === true
      && normalizeAttendanceReportFormulaScope(field.formulaScope) === 'summary'
    ))
    .map(field => ({
      code: field.code,
      name: field.name || field.code,
      category: field.category || 'formula',
      source: field.source || 'custom',
      unit: field.unit || 'text',
      sortOrder: Number(field.sortOrder) || 0,
      configured: Boolean(field.configured),
      systemDefined: field.systemDefined !== false,
      enabled: field.enabled !== false,
      reportVisible: field.reportVisible !== false,
      formulaEnabled: true,
      formulaExpression: field.formulaExpression || '',
      formulaScope: 'summary',
      formulaOutputType: normalizeAttendanceReportFormulaOutputType(field.formulaOutputType, field.unit),
      formulaValid: field.formulaValid !== false,
      formulaError: field.formulaError || null,
      formulaReferences: Array.isArray(field.formulaReferences) ? field.formulaReferences : [],
    }))
    .sort((left, right) => {
      if (left.sortOrder !== right.sortOrder) return left.sortOrder - right.sortOrder
      return left.code.localeCompare(right.code)
    })
}

function buildAttendanceReportPeriodSummaryValueFields(summaryFormulaFields = [], dynamicSubtypeDefinitions = []) {
  const fields = []
  const seen = new Set(Object.values(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS))
  for (const [index, field] of ATTENDANCE_SUMMARY_FORMULA_SOURCE_FIELDS.entries()) {
    if (!field?.code || seen.has(field.code)) continue
    seen.add(field.code)
    fields.push({
      ...field,
      category: 'summary',
      source: 'system',
      sortOrder: 1000 + index,
      systemDefined: true,
      formulaEnabled: false,
    })
  }
  for (const [index, field] of (Array.isArray(summaryFormulaFields) ? summaryFormulaFields : []).entries()) {
    if (!field?.code || seen.has(field.code)) continue
    seen.add(field.code)
    fields.push({
      ...field,
      category: 'formula',
      source: field.source || 'custom',
      sortOrder: 2000 + (Number(field.sortOrder) || index),
      configured: true,
      systemDefined: field.systemDefined !== false,
      formulaEnabled: true,
    })
  }
  const sortedSubtypeDefinitions = [...(Array.isArray(dynamicSubtypeDefinitions) ? dynamicSubtypeDefinitions : [])]
    .filter(field => field?.code)
    .sort((left, right) => {
      const leftSort = Number(left.sortOrder) || 0
      const rightSort = Number(right.sortOrder) || 0
      if (leftSort !== rightSort) return leftSort - rightSort
      return String(left.code).localeCompare(String(right.code))
    })
  for (const [index, field] of sortedSubtypeDefinitions.entries()) {
    if (!field?.code || seen.has(field.code)) continue
    seen.add(field.code)
    fields.push({
      ...field,
      sortOrder: 3000 + (Number(field.sortOrder) || index),
      systemDefined: true,
      formulaEnabled: false,
    })
  }
  return fields
}

function buildAttendanceReportPeriodSummaryActiveValueCodes(summaryFormulaFields = [], dynamicSubtypeDefinitions = []) {
  const codes = new Set(ATTENDANCE_SUMMARY_FORMULA_SOURCE_FIELDS.map(field => field.code))
  for (const field of (Array.isArray(summaryFormulaFields) ? summaryFormulaFields : [])) {
    if (field?.code) codes.add(field.code)
  }
  for (const field of (Array.isArray(dynamicSubtypeDefinitions) ? dynamicSubtypeDefinitions : [])) {
    if (field?.code) codes.add(field.code)
  }
  return codes
}

function buildAttendanceReportPeriodSummaryValueColumns(valueFields) {
  const skeletonIds = new Set(Object.values(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS))
  return (Array.isArray(valueFields) ? valueFields : [])
    .filter(field => field?.code && !skeletonIds.has(field.code))
    .map((field, index) => ({
      id: field.code,
      name: field.name || field.code,
      type: mapReportFieldToMultitableType(field),
      order: 1000 + index,
    }))
}

function attendanceReportPeriodSummaryRowKey(orgId, userId, period) {
  if (period?.cycleId) {
    return `${orgId}:${userId}:cycle:${period.cycleId}`
  }
  return `${orgId}:${userId}:range:${period?.from}:${period?.to}`
}

function buildAttendanceReportPeriodSummarySourceFingerprint(logicalPayload, extraPayload = {}) {
  const excluded = new Set([
    ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.syncedAt,
    ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.fieldFingerprint,
    ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.sourceFingerprint,
  ])
  return buildAttendanceReportSourceFingerprint(logicalPayload, excluded, extraPayload)
}

function buildAttendancePeriodSummarySubtypeTotals(approvedMap) {
  const totals = {}
  if (!(approvedMap instanceof Map)) return totals
  for (const entry of approvedMap.values()) {
    const subtypes = entry?.reportSubtypeMinutes && typeof entry.reportSubtypeMinutes === 'object'
      ? entry.reportSubtypeMinutes
      : {}
    for (const [code, value] of Object.entries(subtypes)) {
      totals[code] = (totals[code] ?? 0) + Number(value ?? 0)
    }
  }
  return totals
}

function getAttendancePeriodSummaryFieldValue(summary, code) {
  if (!summary || !code) return ''
  const formulaValues = summary.formula_values && typeof summary.formula_values === 'object'
    ? summary.formula_values
    : {}
  if (Object.prototype.hasOwnProperty.call(formulaValues, code)) return formulaValues[code]
  const subtypeValues = summary.reportSubtypeMinutes && typeof summary.reportSubtypeMinutes === 'object'
    ? summary.reportSubtypeMinutes
    : {}
  if (Object.prototype.hasOwnProperty.call(subtypeValues, code)) return subtypeValues[code]
  return getAttendancePayrollSummaryFieldValue(summary, code)
}

async function loadAttendancePeriodSummaryEmployeeInfo(db, orgId, userId, from, to) {
  const rows = await db.query(
    `SELECT u.name AS user_name,
            u.username AS username,
            ar.meta AS meta
     FROM users u
     LEFT JOIN LATERAL (
       SELECT meta
       FROM attendance_records
       WHERE user_id = u.id
         AND org_id = $2
         AND work_date BETWEEN $3 AND $4
       ORDER BY work_date DESC
       LIMIT 1
     ) ar ON true
     WHERE u.id = $1
     LIMIT 1`,
    [userId, orgId, from, to],
  )
  const row = rows[0] ?? {}
  const metaRow = { meta: normalizeMetadata(row.meta) }
  return {
    employeeName: firstNonEmptyValue(row.user_name, row.username, userId),
    department: firstNonEmptyValue(readAttendanceRecordMeta(metaRow, ['department', '部门'])),
    attendanceGroup: firstNonEmptyValue(readAttendanceRecordMeta(metaRow, ['attendanceGroup', 'attendance_group', '考勤组'])),
  }
}

async function resolveAttendanceReportPeriodSyncPeriod(db, orgId, params = {}) {
  const cycleIdRaw = String(params?.cycleId || '').trim()
  const hasCycle = Boolean(cycleIdRaw)
  const hasFrom = params?.from !== undefined
  const hasTo = params?.to !== undefined
  const hasDateRangeInput = hasFrom || hasTo
  if (hasCycle && hasDateRangeInput) {
    return {
      ok: false,
      status: 400,
      code: 'VALIDATION_ERROR',
      message: 'Use either cycleId or from/to, not both',
    }
  }
  if (hasCycle) {
    const cycleId = normalizeUuidString(cycleIdRaw)
    if (!cycleId) {
      return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: 'Invalid cycleId' }
    }
    const rows = await db.query(
      'SELECT * FROM attendance_payroll_cycles WHERE id = $1 AND org_id = $2',
      [cycleId, orgId],
    )
    if (!rows.length) {
      return { ok: false, status: 404, code: 'NOT_FOUND', message: 'Payroll cycle not found' }
    }
    const cycle = mapPayrollCycleRow(rows[0])
    // §7 precise window verification (replaces the V1 coarse heuristic): only a cycle whose
    // dates match its template's generated window maps to the month cap downstream.
    const templateWindowMatches = await verifyAttendancePayrollCycleTemplateWindow(db, orgId, cycle)
    return {
      ok: true,
      period: {
        periodType: 'payroll_cycle',
        periodKey: `cycle:${cycle.id}`,
        cycleId: cycle.id,
        // Carried for the comprehensive-hours cap mapping (see
        // docs/development/attendance-comprehensive-hours-payroll-cycle-cap-mapping-design-20260526.md
        // §4/§7). Mirrored top-level (alongside the nested `cycle`) so the builder stays agnostic
        // of the cycle row shape — consistent with how `cycleId` is surfaced.
        templateId: cycle.templateId || null,
        // §7: true only when the cycle's dates equal the window its template would generate. The
        // builder requires this (not just templateId presence) before mapping the month cap.
        templateWindowMatches,
        periodName: cycle.name || cycle.id,
        from: cycle.startDate,
        to: cycle.endDate,
        periodStart: cycle.startDate,
        periodEnd: cycle.endDate,
        cycle,
      },
    }
  }
  if (!hasDateRangeInput) {
    return {
      ok: false,
      status: 400,
      code: 'VALIDATION_ERROR',
      message: 'cycleId or from/to is required',
    }
  }
  if (!hasFrom || !hasTo) {
    return {
      ok: false,
      status: 400,
      code: 'VALIDATION_ERROR',
      message: 'Both from and to are required for date range period sync',
    }
  }
  const dateRange = resolveAttendanceDateRange(params?.from, params?.to)
  if (!dateRange.ok) {
    return { ok: false, status: 400, code: 'VALIDATION_ERROR', message: dateRange.message }
  }
  return {
    ok: true,
    period: {
      periodType: 'date_range',
      periodKey: `range:${dateRange.from}:${dateRange.to}`,
      cycleId: null,
      periodName: `${dateRange.from}..${dateRange.to}`,
      from: dateRange.from,
      to: dateRange.to,
      periodStart: dateRange.from,
      periodEnd: dateRange.to,
    },
  }
}

async function syncAttendanceReportPeriodSummary(context, db, orgId, logger, params) {
  const userId = String(params?.userId || '').trim()
  const period = params?.period
  const empty = { synced: 0, patched: 0, created: 0, skipped: 0, failed: 0, duplicateRowKeys: 0 }
  if (!userId || !period?.from || !period?.to) {
    return { ...empty, failed: 1, reason: 'INVALID_SYNC_PARAMS' }
  }

  const ensured = await ensureAttendanceReportPeriodSummaries(context, orgId, logger)
  if (!ensured.available) {
    return { degraded: true, reason: ensured.reason, ...empty }
  }
  const records = context?.api?.multitable?.records
  const provisioning = context?.api?.multitable?.provisioning
  if (!records?.queryRecords || !records?.createRecord || !records?.patchRecord || !provisioning?.ensureObject) {
    return { degraded: true, reason: 'MULTITABLE_RECORDS_API_UNAVAILABLE', ...empty }
  }

  const formulaOptions = await getAttendanceFormulaRuntimeOptions(db)
  const catalog = await buildAttendanceReportFieldCatalogResponse(context, orgId, logger, {
    provision: false,
    ...formulaOptions,
  })
  const summaryFormulaFields = resolveAttendanceSummaryFormulaFields(catalog.items)
  const managedSummaryFormulaFields = resolveAttendanceReportPeriodSummaryManagedFormulaFields(catalog.items)
  const dynamicSubtype = await loadAttendanceReportDynamicSubtypeContext(db, orgId, logger)
  const valueFields = buildAttendanceReportPeriodSummaryValueFields(managedSummaryFormulaFields, dynamicSubtype.definitions)
  const valueColumns = buildAttendanceReportPeriodSummaryValueColumns(valueFields)
  // Comprehensive-hours system columns are provisioned alongside the catalog value columns
  // but filled separately (not from the catalog value loop). fieldFingerprint stays keyed
  // on valueFields only — these are system columns, not catalog config.
  const allValueColumns = [...valueColumns, ...ATTENDANCE_COMPREHENSIVE_HOURS_PERIOD_VALUE_COLUMNS]
  const activeValueCodes = buildAttendanceReportPeriodSummaryActiveValueCodes(summaryFormulaFields, dynamicSubtype.definitions)
  const fieldFingerprint = buildAttendanceReportFieldConfigFingerprint(valueFields).value

  const baseDescriptor = getAttendanceReportPeriodSummariesDescriptor()
  await provisioning.ensureObject({
    projectId: ensured.projectId,
    descriptor: { ...baseDescriptor, fields: [...baseDescriptor.fields, ...allValueColumns] },
  })
  const logicalIds = [
    ...Object.values(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS),
    ...allValueColumns.map(column => column.id),
  ]
  const fieldIds = typeof provisioning.resolveFieldIds === 'function'
    ? await provisioning.resolveFieldIds({
      projectId: ensured.projectId,
      objectId: ATTENDANCE_REPORT_PERIOD_SUMMARIES_OBJECT_ID,
      fieldIds: logicalIds,
    })
    : Object.fromEntries(logicalIds.map(id => [id, id]))
  const physical = logicalId => fieldIds?.[logicalId] || logicalId

  const result = { ...empty, synced: 1 }
  const syncedAt = new Date().toISOString()
  try {
    const summary = await loadAttendanceSummary(db, orgId, userId, period.from, period.to)
    const approvedMap = await loadApprovedMinutesRange(db, orgId, userId, period.from, period.to)
    const reportSubtypeMinutes = buildAttendancePeriodSummarySubtypeTotals(approvedMap)
    const summaryWithSubtype = {
      ...summary,
      ...reportSubtypeMinutes,
      reportSubtypeMinutes,
    }
    const summaryWithFormulas = await enrichAttendanceSummaryWithFormulaValues(
      context,
      summaryWithSubtype,
      summaryFormulaFields,
    )
    const employee = await loadAttendancePeriodSummaryEmployeeInfo(db, orgId, userId, period.from, period.to)
    const rowKey = attendanceReportPeriodSummaryRowKey(orgId, userId, period)
    const logical = {
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.rowKey]: rowKey,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.orgId]: orgId,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.userId]: userId,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.employeeName]: employee.employeeName,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.department]: employee.department,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.attendanceGroup]: employee.attendanceGroup,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.periodType]: period.periodType,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.periodKey]: period.periodKey,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.cycleId]: period.cycleId || null,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.periodName]: period.periodName || '',
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.periodStart]: period.periodStart || period.from,
      [ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.periodEnd]: period.periodEnd || period.to,
    }
    for (const column of valueColumns) {
      if (!activeValueCodes.has(column.id)) {
        logical[column.id] = null
        continue
      }
      const value = getAttendancePeriodSummaryFieldValue(summaryWithFormulas, column.id)
      logical[column.id] = value === '' && isAttendanceDynamicSubtypeCode(column.id) ? 0 : value
    }
    // Comprehensive-hours metric + cap companion fields. Set AFTER the catalog value loop
    // and BEFORE the source fingerprint so the cap value/source/effective_key are hashed
    // into source_fingerprint (a cap edit → fingerprint change → re-sync). Stale-nulls when
    // no org default applies.
    const settings = await getSettings(db)
    const { actualMinutes } = buildAttendanceComprehensiveActualMinutesFromSummary(summary)
    const comprehensiveHoursValues = buildAttendanceComprehensiveHoursPeriodSummaryValues(
      settings,
      orgId,
      userId,
      period,
      actualMinutes,
    )
    Object.assign(logical, comprehensiveHoursValues)
    const sourceFingerprint = buildAttendanceReportPeriodSummarySourceFingerprint(logical, {
      overtimeSegmentation: buildAttendanceSummaryOvertimeSegmentationFingerprintInput(summaryWithFormulas),
    })

    const data = {}
    for (const [logicalId, value] of Object.entries(logical)) {
      data[physical(logicalId)] = value
    }
    data[physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.fieldFingerprint)] = fieldFingerprint
    data[physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.sourceFingerprint)] = sourceFingerprint
    data[physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.syncedAt)] = syncedAt

    const existing = await records.queryRecords({
      sheetId: ensured.sheetId,
      filters: { [physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.rowKey)]: rowKey },
      limit: 50,
    })
    if (!Array.isArray(existing) || existing.length === 0) {
      await records.createRecord({ sheetId: ensured.sheetId, data })
      result.created += 1
    } else {
      if (existing.length > 1) result.duplicateRowKeys += existing.length - 1
      const target = existing[0]
      const existingData = (target && target.data && typeof target.data === 'object') ? target.data : {}
      const existingSource = existingData[physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.sourceFingerprint)]
      const existingField = existingData[physical(ATTENDANCE_REPORT_PERIOD_SUMMARIES_FIELDS.fieldFingerprint)]
      if (existingSource === sourceFingerprint && existingField === fieldFingerprint) {
        result.skipped += 1
      } else {
        await records.patchRecord({ sheetId: ensured.sheetId, recordId: target.id, changes: data })
        result.patched += 1
      }
    }
  } catch (error) {
    result.failed += 1
    logger?.warn?.('attendance report period summary sync row failed', {
      userId,
      periodKey: period?.periodKey,
      error: error instanceof Error ? error.message : String(error),
    })
  }

  return {
    ...result,
    rowsSynced: result.synced,
    usersScanned: 1,
    usersSynced: result.failed > 0 ? 0 : 1,
    usersFailed: result.failed > 0 ? 1 : 0,
    failedUsers: result.failed > 0 ? [{ userId, failedRows: result.failed }] : [],
    periodType: period.periodType,
    periodKey: period.periodKey,
    cycleId: period.cycleId || null,
    from: period.from,
    to: period.to,
    fieldFingerprint,
    syncedAt,
    multitable: {
      available: true,
      degraded: false,
      projectId: ensured.projectId,
      objectId: ensured.objectId,
      baseId: ensured.baseId || null,
      sheetId: ensured.sheetId || null,
      viewId: ensured.viewId || null,
    },
  }
}

async function syncAttendanceReportPeriodSummariesForUsers(context, db, orgId, logger, params) {
  const period = params?.period
  const explicitUserIds = normalizeAttendanceReportRecordsSyncUserIds(params?.userIds)
  const selection = explicitUserIds.length > 0
    ? {
        userIds: explicitUserIds,
        totalUsers: explicitUserIds.length,
        page: 1,
        pageSize: explicitUserIds.length,
        hasNextPage: false,
        userSelection: 'explicit',
      }
    : await loadAttendanceReportRecordsSyncUserPage(db, orgId, period.from, period.to, {
      page: params?.page,
      pageSize: params?.pageSize,
    })

  const aggregate = createAttendanceReportRecordsSyncEmptyResult({
    totalUsers: selection.totalUsers,
    page: selection.page,
    pageSize: selection.pageSize,
    hasNextPage: selection.hasNextPage,
    userSelection: selection.userSelection,
    periodType: period.periodType,
    periodKey: period.periodKey,
    cycleId: period.cycleId || null,
    from: period.from,
    to: period.to,
  })

  for (const userId of selection.userIds) {
    aggregate.usersScanned += 1
    try {
      const result = await syncAttendanceReportPeriodSummary(context, db, orgId, logger, { period, userId })
      if (result.degraded) {
        return {
          ...aggregate,
          ...result,
          rowsSynced: aggregate.synced,
          totalUsers: selection.totalUsers,
          page: selection.page,
          pageSize: selection.pageSize,
          hasNextPage: selection.hasNextPage,
          userSelection: selection.userSelection,
        }
      }
      aggregate.usersSynced += 1
      aggregate.synced += Number(result.synced ?? 0)
      aggregate.rowsSynced = aggregate.synced
      aggregate.created += Number(result.created ?? 0)
      aggregate.patched += Number(result.patched ?? 0)
      aggregate.skipped += Number(result.skipped ?? 0)
      aggregate.failed += Number(result.failed ?? 0)
      aggregate.duplicateRowKeys += Number(result.duplicateRowKeys ?? 0)
      if (Number(result.failed ?? 0) > 0) {
        aggregate.failedUsers.push({ userId, failedRows: Number(result.failed ?? 0) })
      }
      if (result.fieldFingerprint) aggregate.fieldFingerprint = result.fieldFingerprint
      if (result.syncedAt) aggregate.syncedAt = result.syncedAt
      if (result.multitable) aggregate.multitable = result.multitable
    } catch (error) {
      aggregate.usersFailed += 1
      aggregate.failed += 1
      aggregate.failedUsers.push({
        userId,
        error: error instanceof Error ? error.message : String(error),
      })
      logger?.warn?.('attendance report period summaries user sync failed', {
        userId,
        periodKey: period?.periodKey,
        error: error instanceof Error ? error.message : String(error),
      })
    }
  }
  aggregate.usersFailed = aggregate.failedUsers.length
  return aggregate
}

async function loadAttendanceReportFieldCatalog(context, orgId) {
  const projectId = getAttendanceReportFieldProjectId(orgId)
  const multitable = context?.api?.multitable
  const provisioning = multitable?.provisioning
  if (!provisioning?.findObjectSheet || !multitable?.records?.queryRecords) {
    return {
      available: false,
      reason: 'MULTITABLE_API_UNAVAILABLE',
      projectId,
      objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
      sheetId: null,
      viewId: null,
      fieldIds: {},
    }
  }

  const sheet = await provisioning.findObjectSheet({
    projectId,
    objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
  })
  if (!sheet) {
    return {
      available: false,
      reason: 'CATALOG_NOT_PROVISIONED',
      projectId,
      objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
      sheetId: null,
      viewId: null,
      fieldIds: {},
    }
  }

  const logicalFieldIds = Object.values(ATTENDANCE_REPORT_FIELD_CATALOG_FIELDS)
  let fieldIds = {}
  if (typeof provisioning.resolveFieldIds === 'function') {
    fieldIds = await provisioning.resolveFieldIds({
      projectId,
      objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
      fieldIds: logicalFieldIds,
    })
  } else if (typeof provisioning.getFieldId === 'function') {
    fieldIds = Object.fromEntries(logicalFieldIds.map(fieldId => [
      fieldId,
      provisioning.getFieldId(projectId, ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID, fieldId),
    ]))
  }

  return {
    available: true,
    reason: null,
    projectId,
    objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
    baseId: sheet.baseId || null,
    sheetId: sheet.id,
    viewId: getAttendanceReportFieldCatalogViewId(projectId),
    fieldIds,
    seeded: 0,
    existing: 0,
    seedSkipped: true,
  }
}

function buildAttendanceReportFieldCatalogFallback(orgId, reason, error, options = {}) {
  const projectId = getAttendanceReportFieldProjectId(orgId)
  const items = mergeAttendanceReportFieldDefinitions([], {}, {
    rawAliasesAllowed: options.rawAliasesAllowed,
    extraSystemDefinitions: options.extraSystemDefinitions,
  })
  const multitable = {
    available: false,
    degraded: true,
    reason,
    error: error instanceof Error ? error.message : undefined,
    projectId,
    objectId: ATTENDANCE_REPORT_FIELD_CATALOG_OBJECT_ID,
    sheetId: null,
    viewId: null,
    seeded: 0,
    existing: 0,
  }
  const formulaDependencyGraph = buildAttendanceReportFormulaDependencyGraph(items)
  return {
    categories: cloneAttendanceReportFieldCategories(),
    items,
    droppedReservedCodes: [],
    multitable,
    reportFieldConfig: buildAttendanceReportFieldConfig({
      fields: resolveAttendanceRecordReportFields(items),
      formulaSourceFields: resolveAttendanceFormulaSourceFields(items),
      formulaDependencyGraph,
      multitable,
    }),
  }
}

const ATTENDANCE_EMPTY_DYNAMIC_SUBTYPE_CONTEXT = Object.freeze({
  definitions: Object.freeze([]),
  leaveTypeCodeToFieldCode: Object.freeze({}),
  overtimeRuleIdToFieldCode: Object.freeze({}),
  degraded: false,
})

async function loadAttendanceReportDynamicSubtypeContext(db, orgId, logger) {
  if (!db || typeof db.query !== 'function') {
    return ATTENDANCE_EMPTY_DYNAMIC_SUBTYPE_CONTEXT
  }
  const targetOrg = orgId || DEFAULT_ORG_ID
  let leaveTypes = []
  let overtimeRules = []
  try {
    leaveTypes = await db.query(
      `SELECT id, code, name, is_active
       FROM attendance_leave_types
       WHERE org_id = $1 AND is_active = true`,
      [targetOrg],
    )
    overtimeRules = await db.query(
      `SELECT id, name, is_active
       FROM attendance_overtime_rules
       WHERE org_id = $1 AND is_active = true`,
      [targetOrg],
    )
  } catch (error) {
    if (isDatabaseSchemaError(error)) {
      logger?.warn?.('Attendance dynamic subtype fields degraded: schema unavailable')
      return { ...ATTENDANCE_EMPTY_DYNAMIC_SUBTYPE_CONTEXT, degraded: true }
    }
    logger?.warn?.('Attendance dynamic subtype fields degraded', error)
    return { ...ATTENDANCE_EMPTY_DYNAMIC_SUBTYPE_CONTEXT, degraded: true }
  }

  const usedCodes = new Set(ATTENDANCE_REPORT_FORMULA_RESERVED_CODES)
  for (const field of cloneAttendanceReportFieldDefinitions()) usedCodes.add(field.code)

  const leave = buildAttendanceLeaveSubtypeReportFieldDefinitions(leaveTypes, usedCodes)
  const overtime = buildAttendanceOvertimeSubtypeReportFieldDefinitions(overtimeRules, usedCodes)
  return {
    definitions: [...leave.definitions, ...overtime.definitions],
    leaveTypeCodeToFieldCode: leave.leaveTypeCodeToFieldCode,
    overtimeRuleIdToFieldCode: overtime.overtimeRuleIdToFieldCode,
    degraded: false,
  }
}

async function buildAttendanceReportFieldCatalogResponse(context, orgId, logger, options = {}) {
  const rawAliasesAllowed = options.rawAliasesAllowed !== false
  const dynamicSubtype = await loadAttendanceReportDynamicSubtypeContext(
    context?.api?.database,
    orgId,
    logger,
  )
  let catalog
  try {
    catalog = options.provision === true
      ? await ensureAttendanceReportFieldCatalog(context, orgId, logger, { seedRecords: options.seedRecords !== false })
      : await loadAttendanceReportFieldCatalog(context, orgId, logger)
  } catch (error) {
    logger?.warn?.('Attendance report field catalog provisioning degraded', error)
    return buildAttendanceReportFieldCatalogFallback(orgId, 'PROVISIONING_FAILED', error, {
      rawAliasesAllowed,
      extraSystemDefinitions: dynamicSubtype.definitions,
    })
  }

  if (!catalog.available) {
    return buildAttendanceReportFieldCatalogFallback(orgId, catalog.reason || 'MULTITABLE_UNAVAILABLE', undefined, {
      rawAliasesAllowed,
      extraSystemDefinitions: dynamicSubtype.definitions,
    })
  }

  try {
    const records = context.api.multitable.records?.queryRecords
      ? await context.api.multitable.records.queryRecords({
        sheetId: catalog.sheetId,
        orderBy: {
          fieldId: catalog.fieldIds?.[ATTENDANCE_REPORT_FIELD_CATALOG_FIELDS.sortOrder] || ATTENDANCE_REPORT_FIELD_CATALOG_FIELDS.sortOrder,
          direction: 'asc',
        },
        limit: 1000,
      })
      : []
    const items = mergeAttendanceReportFieldDefinitions(records, catalog.fieldIds, {
      rawAliasesAllowed,
      extraSystemDefinitions: dynamicSubtype.definitions,
    })
    const droppedReservedCodes = getAttendanceReportFieldDroppedReservedCodes(records, catalog.fieldIds)
    const formulaDependencyGraph = buildAttendanceReportFormulaDependencyGraph(items)
    const multitable = {
      available: true,
      degraded: false,
      projectId: catalog.projectId,
      objectId: catalog.objectId,
      baseId: catalog.baseId || null,
      sheetId: catalog.sheetId,
      viewId: catalog.viewId,
      seeded: catalog.seeded,
      existing: catalog.existing,
      recordCount: records.length,
    }
    return {
      categories: cloneAttendanceReportFieldCategories(),
      items,
      droppedReservedCodes,
      multitable,
      reportFieldConfig: buildAttendanceReportFieldConfig({
        fields: resolveAttendanceRecordReportFields(items),
        formulaSourceFields: resolveAttendanceFormulaSourceFields(items),
        formulaDependencyGraph,
        multitable,
      }),
    }
  } catch (error) {
    logger?.warn?.('Attendance report field catalog read degraded', error)
    return buildAttendanceReportFieldCatalogFallback(orgId, 'READ_FAILED', error, {
      rawAliasesAllowed,
      extraSystemDefinitions: dynamicSubtype.definitions,
    })
  }
}

const ATTENDANCE_RECORD_REPORT_FIELD_CODES = Object.freeze([
  'work_date',
  'employee_name',
  'employee_no',
  'department',
  'position',
  'hire_date',
  'attendance_group',
  'punch_times',
  'punch_result',
  'punch_in_1',
  'punch_out_1',
  'punch_in_2',
  'punch_out_2',
  'punch_in_3',
  'punch_out_3',
  'punch_result_in_1',
  'punch_result_out_1',
  'punch_result_in_2',
  'punch_result_out_2',
  'punch_result_in_3',
  'punch_result_out_3',
  'approval_forms',
  'expected_attendance_days',
  'correction_count',
  'attendance_shift',
  'attendance_days',
  'rest_days',
  'work_duration',
  'business_trip_duration',
  'outing_duration',
  'attendance_result',
  'shift',
  'late_count',
  'late_duration',
  'severe_late_count',
  'severe_late_duration',
  'absence_late_count',
  'early_leave_count',
  'early_leave_duration',
  'missing_clock_in_count',
  'missing_clock_out_count',
  'absenteeism_days',
  'leave_duration',
  'overtime_approval_duration',
  'workday_overtime_duration',
  'restday_overtime_duration',
  'holiday_overtime_duration',
])

const ATTENDANCE_RECORD_REPORT_FIELD_CODE_SET = new Set(ATTENDANCE_RECORD_REPORT_FIELD_CODES)

function resolveAttendanceRecordReportFields(items) {
  const sourceItems = Array.isArray(items) && items.length > 0
    ? items
    : mergeAttendanceReportFieldDefinitions([], {})
  return sourceItems
    .filter(field => (
      field
      && field.enabled !== false
      && field.reportVisible !== false
      && (
        ATTENDANCE_RECORD_REPORT_FIELD_CODE_SET.has(field.code)
        || (field.formulaEnabled === true && normalizeAttendanceReportFormulaScope(field.formulaScope) === 'record')
        || (field.systemDefined !== false && isAttendanceDynamicSubtypeCode(field.code))
      )
    ))
    .map(field => ({
      code: field.code,
      name: field.name || field.code,
      category: field.category || 'attendance',
      categoryLabel: field.categoryLabel || getAttendanceReportFieldCategory(field.category).label,
      unit: field.unit || 'text',
      sortOrder: Number(field.sortOrder) || 0,
      source: field.source || 'system',
      description: field.description || '',
      systemDefined: field.systemDefined !== false,
      configured: Boolean(field.configured),
      formulaEnabled: Boolean(field.formulaEnabled),
      formulaExpression: field.formulaExpression || '',
      formulaScope: normalizeAttendanceReportFormulaScope(field.formulaScope),
      formulaOutputType: normalizeAttendanceReportFormulaOutputType(field.formulaOutputType, field.unit),
      formulaValid: field.formulaValid !== false,
      formulaError: field.formulaError || null,
      formulaReferences: Array.isArray(field.formulaReferences) ? field.formulaReferences : [],
      exportKey: field.code,
    }))
    .sort((left, right) => {
      if (left.sortOrder !== right.sortOrder) return left.sortOrder - right.sortOrder
      return left.code.localeCompare(right.code)
    })
}

function resolveAttendanceFormulaSourceFields(items) {
  const sourceItems = Array.isArray(items) && items.length > 0
    ? items
    : mergeAttendanceReportFieldDefinitions([], {})
  return sourceItems
    .filter(field => (
      field
      && field.code
      && field.enabled !== false
      && field.formulaEnabled !== true
      && (field.systemDefined !== false || isCustomAttendanceFormulaSourceField(field))
    ))
    .map(field => ({
      code: field.code,
      source: field.source || 'system',
      systemDefined: field.systemDefined !== false,
      internalKey: field.internalKey || field.code,
      formulaSourceMode: normalizeAttendanceReportFormulaSourceMode(field.formulaSourceMode),
    }))
}

async function loadAttendanceRecordReportFields(context, orgId, logger, options = {}) {
  const catalog = await buildAttendanceReportFieldCatalogResponse(context, orgId, logger, {
    provision: false,
    rawAliasesAllowed: options.rawAliasesAllowed,
  })
  return {
    fields: resolveAttendanceRecordReportFields(catalog.items),
    formulaSourceFields: resolveAttendanceFormulaSourceFields(catalog.items),
    multitable: catalog.multitable,
  }
}

function normalizeAttendanceReportFieldFingerprintItems(fields) {
  return Array.isArray(fields)
    ? fields
      .map(field => ({
        code: String(field?.code || ''),
        name: String(field?.name || ''),
        category: String(field?.category || ''),
        unit: String(field?.unit || ''),
        sortOrder: Number(field?.sortOrder) || 0,
        source: String(field?.source || ''),
        configured: Boolean(field?.configured),
        systemDefined: field?.systemDefined !== false,
        formulaEnabled: Boolean(field?.formulaEnabled),
        formulaExpression: String(field?.formulaExpression || ''),
        formulaScope: String(field?.formulaScope || ''),
        formulaOutputType: String(field?.formulaOutputType || ''),
        formulaValid: field?.formulaValid !== false,
      }))
      .filter(field => field.code)
      .sort((left, right) => {
        if (left.sortOrder !== right.sortOrder) return left.sortOrder - right.sortOrder
        return left.code.localeCompare(right.code)
      })
    : []
}

function normalizeAttendanceFormulaSourceFingerprintItems(fields) {
  return Array.isArray(fields)
    ? fields
      .filter(field => field?.systemDefined === false)
      .map(field => ({
        code: String(field?.code || ''),
        source: String(field?.source || ''),
        systemDefined: false,
        internalKey: String(field?.internalKey || ''),
        formulaSourceMode: normalizeAttendanceReportFormulaSourceMode(field?.formulaSourceMode),
      }))
      .filter(field => field.code && field.formulaSourceMode !== 'none')
      .sort((left, right) => left.code.localeCompare(right.code))
    : []
}

function buildAttendanceReportFieldConfigFingerprint(fields, options = {}) {
  const normalized = Array.isArray(fields)
    ? normalizeAttendanceReportFieldFingerprintItems(fields)
    : []
  const formulaSourceFields = normalizeAttendanceFormulaSourceFingerprintItems(options.formulaSourceFields)
  const fingerprintPayload = formulaSourceFields.length > 0
    ? { fields: normalized, formulaSourceFields }
    : normalized
  const value = crypto
    .createHash('sha1')
    .update(JSON.stringify(fingerprintPayload))
    .digest('hex')
  return {
    algorithm: 'sha1',
    value,
    fieldCount: normalized.length,
    codes: normalized.map(field => field.code),
  }
}

function buildAttendanceReportFieldConfig(reportFields) {
  const fields = Array.isArray(reportFields?.fields) ? reportFields.fields : []
  const formulaSourceFields = Array.isArray(reportFields?.formulaSourceFields)
    ? reportFields.formulaSourceFields
    : []
  const formulaDependencyGraph = reportFields?.formulaDependencyGraph || buildAttendanceReportFormulaDependencyGraph([])
  return {
    multitable: reportFields?.multitable || {
      available: false,
      degraded: true,
      reason: 'REPORT_FIELD_CONFIG_UNAVAILABLE',
    },
    fieldsFingerprint: buildAttendanceReportFieldConfigFingerprint(fields, { formulaSourceFields }),
    formulaDependencyGraph,
  }
}

function buildAttendanceReportFieldConfigHeaders(reportFieldConfig) {
  const fingerprint = reportFieldConfig?.fieldsFingerprint || {}
  const multitable = reportFieldConfig?.multitable || {}
  const headers = {}
  const algorithm = String(fingerprint.algorithm || '').trim()
  const value = String(fingerprint.value || '').trim()
  const fieldCount = Number(fingerprint.fieldCount)
  const codes = Array.isArray(fingerprint.codes)
    ? fingerprint.codes.map(code => String(code || '').trim()).filter(Boolean)
    : []
  if (algorithm) headers['X-Attendance-Report-Fields-Fingerprint-Algorithm'] = algorithm
  if (value) headers['X-Attendance-Report-Fields-Fingerprint'] = value
  if (Number.isFinite(fieldCount)) headers['X-Attendance-Report-Fields-Count'] = String(fieldCount)
  if (codes.length > 0) headers['X-Attendance-Report-Fields-Codes'] = codes.join(',')
  const projectId = String(multitable.projectId || '').trim()
  const objectId = String(multitable.objectId || '').trim()
  const sheetId = String(multitable.sheetId || '').trim()
  const viewId = String(multitable.viewId || '').trim()
  if (projectId) headers['X-Attendance-Report-Fields-Project-Id'] = projectId
  if (objectId) headers['X-Attendance-Report-Fields-Object-Id'] = objectId
  if (sheetId) headers['X-Attendance-Report-Fields-Sheet-Id'] = sheetId
  if (viewId) headers['X-Attendance-Report-Fields-View-Id'] = viewId
  return headers
}

function setAttendanceReportFieldConfigHeaders(res, reportFieldConfig) {
  for (const [key, value] of Object.entries(buildAttendanceReportFieldConfigHeaders(reportFieldConfig))) {
    res.setHeader(key, value)
  }
}

function firstNonEmptyValue(...values) {
  for (const value of values) {
    if (Array.isArray(value)) {
      const joined = value.map(item => String(item ?? '').trim()).filter(Boolean).join(', ')
      if (joined) return joined
      continue
    }
    const normalized = typeof value === 'string' ? value.trim() : value
    if (normalized !== undefined && normalized !== null && normalized !== '') return normalized
  }
  return ''
}

function readAttendanceRecordMeta(row, keys) {
  const meta = normalizeMetadata(row?.meta)
  for (const key of keys) {
    if (Object.prototype.hasOwnProperty.call(meta, key)) {
      return meta[key]
    }
  }
  return undefined
}

function normalizeAttendanceReportDateOnly(value) {
  return normalizeDateOnlyValue(value) ?? firstNonEmptyValue(value)
}

function readAttendanceRecordMinutes(row, keys, fallback = 0) {
  const value = readAttendanceRecordMeta(row, keys)
  const parsed = Number(value)
  if (Number.isFinite(parsed)) return parsed
  return fallback
}

function normalizeApprovedOvertimeSegmentationProjection(value) {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null
  const version = Number(value.version ?? value.overtimeSegmentationVersion ?? value.overtime_segmentation_version)
  if (!Number.isFinite(version)) return null
  return {
    version,
    workdayOvertimeMinutes: normalizeOvertimeSegmentationMinutes(value.workdayOvertimeMinutes ?? value.workday_overtime_minutes),
    restdayOvertimeMinutes: normalizeOvertimeSegmentationMinutes(value.restdayOvertimeMinutes ?? value.restday_overtime_minutes),
    holidayOvertimeMinutes: normalizeOvertimeSegmentationMinutes(value.holidayOvertimeMinutes ?? value.holiday_overtime_minutes),
    compTimeGrantMinutes: normalizeOvertimeSegmentationMinutes(value.compTimeGrantMinutes ?? value.comp_time_grant_minutes),
  }
}

function readApprovedOvertimeSegmentationProjection(row) {
  return normalizeApprovedOvertimeSegmentationProjection(
    readAttendanceRecordMeta(row, ['approvedOvertimeSegmentation', 'approved_overtime_segmentation']),
  )
}

function readAttendanceRecordOvertimeSegments(row) {
  const projection = readApprovedOvertimeSegmentationProjection(row)
  if (projection) return { ...projection, projected: true }
  const isWorkday = row?.is_workday !== false
  const overtimeMinutes = readAttendanceRecordMinutes(row, ['overtime_minutes', 'overtimeMinutes'], 0)
  return {
    version: null,
    projected: false,
    workdayOvertimeMinutes: isWorkday ? overtimeMinutes : 0,
    restdayOvertimeMinutes: !isWorkday ? overtimeMinutes : 0,
    holidayOvertimeMinutes: readAttendanceRecordMinutes(row, ['holiday_overtime_minutes', 'holidayOvertimeMinutes'], 0),
    compTimeGrantMinutes: readAttendanceRecordMinutes(row, ['comp_time_grant_minutes', 'compTimeGrantMinutes'], 0),
  }
}

function buildAttendanceRecordOvertimeSegmentationFingerprintInput(row) {
  const projection = readApprovedOvertimeSegmentationProjection(row)
  if (!projection) return null
  return projection
}

function buildAttendanceSummaryOvertimeSegmentationFingerprintInput(summary) {
  return {
    version: attendanceSummaryNumber(summary, 'overtime_segmentation_version') || null,
    workdayOvertimeMinutes: attendanceSummaryNumber(summary, 'workday_overtime_minutes'),
    restdayOvertimeMinutes: attendanceSummaryNumber(summary, 'restday_overtime_minutes'),
    holidayOvertimeMinutes: attendanceSummaryNumber(summary, 'holiday_overtime_minutes'),
    compTimeGrantMinutes: attendanceSummaryNumber(summary, 'comp_time_grant_minutes'),
  }
}

function formatAttendanceRecordReportDateTime(value, timezone) {
  return value ? formatDateTimeForCsv(value, timezone) : ''
}

function getAttendanceRecordReportFieldValue(row, fieldCode) {
  const timezone = row?.timezone
  const workDate = normalizeDateOnly(row?.work_date) ?? String(row?.work_date ?? '').slice(0, 10)
  const status = String(row?.status ?? '')
  const isWorkday = row?.is_workday !== false
  const workMinutes = Number(row?.work_minutes ?? 0)
  const lateMinutes = Number(row?.late_minutes ?? 0)
  const earlyLeaveMinutes = Number(row?.early_leave_minutes ?? 0)
  const leaveMinutes = readAttendanceRecordMinutes(row, ['leave_minutes', 'leaveMinutes'], 0)
  const overtimeMinutes = readAttendanceRecordMinutes(row, ['overtime_minutes', 'overtimeMinutes'], 0)
  const overtimeSegments = readAttendanceRecordOvertimeSegments(row)

  if (isAttendanceDynamicSubtypeCode(fieldCode)) {
    const subtypeMap = readAttendanceRecordMeta(row, ['reportSubtypeMinutes', 'report_subtype_minutes'])
    const value = subtypeMap && typeof subtypeMap === 'object' ? Number(subtypeMap[fieldCode]) : 0
    return Number.isFinite(value) ? value : 0
  }

  switch (fieldCode) {
    case 'work_date':
      return workDate
    case 'employee_name':
      return firstNonEmptyValue(row?.user_name, row?.username, row?.user_id)
    case 'employee_no':
      return firstNonEmptyValue(
        row?.employee_no,
        row?.employeeNo,
        row?.user?.employee_no,
        row?.user?.employeeNo,
        readAttendanceRecordMeta(row, ['empNo', 'employeeNo', 'employee_no', '工号']),
        row?.user_id,
      )
    case 'department':
      return firstNonEmptyValue(
        row?.department,
        row?.user_department,
        row?.user?.department,
        readAttendanceRecordMeta(row, ['department', '部门']),
      )
    case 'position':
      return firstNonEmptyValue(
        row?.position,
        row?.user_position,
        row?.user?.position,
        readAttendanceRecordMeta(row, ['position', 'role', 'roleTags', 'role_tags', '职位']),
      )
    case 'hire_date':
      return normalizeAttendanceReportDateOnly(firstNonEmptyValue(
        row?.hire_date,
        row?.hireDate,
        row?.user_hire_date,
        row?.user?.hire_date,
        row?.user?.hireDate,
        readAttendanceRecordMeta(row, ['hireDate', 'hire_date', '入职日期']),
      ))
    case 'attendance_group':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['attendanceGroup', 'attendance_group', '考勤组']))
    case 'punch_times':
      return [
        formatAttendanceRecordReportDateTime(row?.first_in_at, timezone),
        formatAttendanceRecordReportDateTime(row?.last_out_at, timezone),
      ].filter(Boolean).join(' / ')
    case 'punch_result':
    case 'attendance_result':
      return status
    case 'punch_in_1':
      return formatAttendanceRecordReportDateTime(row?.first_in_at, timezone)
    case 'punch_out_1':
      return formatAttendanceRecordReportDateTime(row?.last_out_at, timezone)
    case 'punch_in_2':
      return formatAttendanceRecordReportDateTime(readAttendanceRecordMeta(row, ['clockIn2', 'clock_in_2', '上班2打卡时间']), timezone)
    case 'punch_out_2':
      return formatAttendanceRecordReportDateTime(readAttendanceRecordMeta(row, ['clockOut2', 'clock_out_2', '下班2打卡时间']), timezone)
    case 'punch_in_3':
      return formatAttendanceRecordReportDateTime(readAttendanceRecordMeta(row, ['clockIn3', 'clock_in_3', '上班3打卡时间']), timezone)
    case 'punch_out_3':
      return formatAttendanceRecordReportDateTime(readAttendanceRecordMeta(row, ['clockOut3', 'clock_out_3', '下班3打卡时间']), timezone)
    case 'punch_result_in_1':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultIn1', 'punch_result_in_1', '上班1打卡结果']))
    case 'punch_result_out_1':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultOut1', 'punch_result_out_1', '下班1打卡结果']))
    case 'punch_result_in_2':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultIn2', 'punch_result_in_2', '上班2打卡结果']))
    case 'punch_result_out_2':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultOut2', 'punch_result_out_2', '下班2打卡结果']))
    case 'punch_result_in_3':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultIn3', 'punch_result_in_3', '上班3打卡结果']))
    case 'punch_result_out_3':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['punchResultOut3', 'punch_result_out_3', '下班3打卡结果']))
    case 'approval_forms':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['approvalSummary', 'approval_summary', 'attendance_approve', '关联的审批单']))
    case 'expected_attendance_days':
      return isWorkday ? 1 : 0
    case 'correction_count':
      return Number(readAttendanceRecordMeta(row, ['correction_count', 'correctionCount']) ?? (status === 'adjusted' ? 1 : 0))
    case 'attendance_shift':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['attendanceClass', 'attendance_class', '出勤班次']))
    case 'attendance_days':
      return isWorkday && !['absent', 'off'].includes(status) ? 1 : 0
    case 'rest_days':
      return isWorkday ? 0 : 1
    case 'work_duration':
      return workMinutes
    case 'business_trip_duration':
      return readAttendanceRecordMinutes(row, ['business_trip_minutes', 'businessTripMinutes', 'businessTripDuration'], 0)
    case 'outing_duration':
      return readAttendanceRecordMinutes(row, ['outing_minutes', 'outingMinutes', 'outingDuration'], 0)
    case 'shift':
      return firstNonEmptyValue(readAttendanceRecordMeta(row, ['shiftName', 'shift_name', '班次']), row?.workday_context?.shiftName)
    case 'late_count':
      return lateMinutes > 0 ? 1 : 0
    case 'late_duration':
      return lateMinutes
    case 'severe_late_count':
      return Number(readAttendanceRecordMeta(row, ['severe_late_count', 'severeLateCount']) ?? 0)
    case 'severe_late_duration':
      return readAttendanceRecordMinutes(row, ['severe_late_minutes', 'severeLateMinutes'], 0)
    case 'absence_late_count':
      return Number(readAttendanceRecordMeta(row, ['absence_late_count', 'absenceLateCount']) ?? 0)
    case 'early_leave_count':
      return earlyLeaveMinutes > 0 ? 1 : 0
    case 'early_leave_duration':
      return earlyLeaveMinutes
    case 'missing_clock_in_count':
      return isWorkday && !row?.first_in_at ? 1 : 0
    case 'missing_clock_out_count':
      return isWorkday && !row?.last_out_at ? 1 : 0
    case 'absenteeism_days':
      return status === 'absent' ? 1 : 0
    case 'leave_duration':
      return leaveMinutes
    case 'overtime_approval_duration':
      return overtimeMinutes
    case 'workday_overtime_duration':
      return overtimeSegments.workdayOvertimeMinutes
    case 'restday_overtime_duration':
      return overtimeSegments.restdayOvertimeMinutes
    case 'holiday_overtime_duration':
      return overtimeSegments.holidayOvertimeMinutes
    default:
      return ''
  }
}

function attendanceFormulaLiteral(value) {
  if (value === null || value === undefined || value === '') return '0'
  if (typeof value === 'number') return Number.isFinite(value) ? String(value) : '0'
  if (typeof value === 'boolean') return value ? 'TRUE' : 'FALSE'
  if (value instanceof Date) return JSON.stringify(value.toISOString())
  const parsed = Number(value)
  if (Number.isFinite(parsed) && String(value).trim() !== '') return String(parsed)
  return JSON.stringify(String(value))
}

function buildAttendanceReportFormulaValueMap(row, formulaSourceFields, options = {}) {
  const values = {}
  for (const field of formulaSourceFields || []) {
    if (!field?.code) continue
    if (field.systemDefined === false) {
      values[field.code] = getAttendanceCustomFormulaSourceValue(row, field)
      continue
    }
    values[field.code] = getAttendanceRecordReportFieldValue(row, field.code)
  }
  if (options.rawAliasesAllowed !== false) {
    const overtimeSegments = readAttendanceRecordOvertimeSegments(row)
    values.work_minutes = Number(row?.work_minutes ?? 0)
    values.late_minutes = Number(row?.late_minutes ?? 0)
    values.early_leave_minutes = Number(row?.early_leave_minutes ?? 0)
    values.leave_minutes = readAttendanceRecordMinutes(row, ['leave_minutes', 'leaveMinutes'], 0)
    values.overtime_minutes = readAttendanceRecordMinutes(row, ['overtime_minutes', 'overtimeMinutes'], 0)
    values.workday_overtime_minutes = overtimeSegments.workdayOvertimeMinutes
    values.restday_overtime_minutes = overtimeSegments.restdayOvertimeMinutes
    values.holiday_overtime_minutes = overtimeSegments.holidayOvertimeMinutes
    values.comp_time_grant_minutes = overtimeSegments.compTimeGrantMinutes
  }
  return values
}

function getAttendanceCustomFormulaSourceValue(row, field) {
  const mode = normalizeAttendanceReportFormulaSourceMode(field?.formulaSourceMode)
  if (mode === 'meta') return readAttendanceRecordMeta(row, [field.code])
  if (mode === 'internal_key') return readAttendanceFormulaPathValue(row, field.internalKey)
  if (mode === 'alias') {
    return readAttendanceCustomFormulaAliasValue(
      row,
      normalizeCatalogString(field.internalKey, field.code),
    )
  }
  return undefined
}

function resolveAttendanceReportFormulaExpression(expression, values) {
  return normalizeAttendanceReportFormulaExpression(expression)
    .replace(ATTENDANCE_REPORT_FORMULA_REFERENCE_PATTERN, (_match, reference) => (
      attendanceFormulaLiteral(Object.prototype.hasOwnProperty.call(values, reference) ? values[reference] : 0)
    ))
}

function formatAttendanceReportFormulaValue(value, outputType) {
  if (typeof value === 'string' && value.startsWith('#')) return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  const type = normalizeAttendanceReportFormulaOutputType(outputType)
  if (type === 'number' || type === 'duration_minutes') {
    const parsed = Number(value)
    return Number.isFinite(parsed) ? parsed : ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  }
  if (type === 'boolean') return Boolean(value)
  if (type === 'date') {
    if (value instanceof Date) return value.toISOString()
    return String(value ?? '')
  }
  return value === null || value === undefined ? '' : String(value)
}

async function evaluateAttendanceReportFormulaField(context, row, field, formulaSourceFields, options = {}) {
  if (!field?.formulaEnabled) return getAttendanceRecordReportFieldValue(row, field?.code)
  if (field.formulaValid === false) return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  if (options.rawAliasesAllowed === false) {
    const references = Array.isArray(field.formulaReferences) && field.formulaReferences.length > 0
      ? field.formulaReferences
      : extractAttendanceReportFormulaReferences(field.formulaExpression)
    if (references.some(reference => ATTENDANCE_REPORT_FORMULA_RESERVED_CODES.has(reference))) {
      return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
    }
  }

  const values = buildAttendanceReportFormulaValueMap(row, formulaSourceFields, {
    rawAliasesAllowed: options.rawAliasesAllowed,
  })
  const expression = resolveAttendanceReportFormulaExpression(field.formulaExpression, values)
  const formulaApi = context?.api?.formula
  if (!formulaApi?.calculateFormula) return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE

  try {
    const result = await Promise.resolve(formulaApi.calculateFormula(expression))
    return formatAttendanceReportFormulaValue(result, field.formulaOutputType)
  } catch {
    return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  }
}

async function previewAttendanceReportFormula(context, expression, sample, fields, options = {}) {
  const sampleValues = sample && typeof sample === 'object' && !Array.isArray(sample) ? sample : {}
  const validation = validateAttendanceReportFormulaExpression(expression, {
    fields,
    rawAliasesAllowed: options.rawAliasesAllowed,
    scope: options.scope,
  })
  if (!validation.valid) {
    return {
      ok: false,
      value: null,
      references: validation.references,
      error: validation.error,
    }
  }

  const values = {}
  for (const reference of validation.references) {
    values[reference] = Object.prototype.hasOwnProperty.call(sampleValues, reference)
      ? sampleValues[reference]
      : 0
  }
  const resolvedExpression = resolveAttendanceReportFormulaExpression(expression, values)
  const formulaApi = context?.api?.formula
  if (!formulaApi?.calculateFormula) {
    return {
      ok: false,
      value: null,
      references: validation.references,
      error: 'Formula API is unavailable.',
    }
  }

  try {
    const value = await Promise.resolve(formulaApi.calculateFormula(resolvedExpression))
    if (typeof value === 'string' && value.startsWith('#')) {
      return {
        ok: false,
        value: ATTENDANCE_REPORT_FORMULA_ERROR_VALUE,
        references: validation.references,
        error: 'Formula evaluation failed.',
      }
    }
    return {
      ok: true,
      value,
      references: validation.references,
      error: null,
    }
  } catch (error) {
    return {
      ok: false,
      value: null,
      references: validation.references,
      error: error instanceof Error ? error.message : 'Formula evaluation failed.',
    }
  }
}

function buildAttendanceRecordReportExportItem(row, reportFields) {
  return Object.fromEntries(reportFields.map(field => [
    field.exportKey || field.code,
    getAttendanceRecordReportFieldValue(row, field.code),
  ]))
}

async function buildAttendanceRecordReportExportItemAsync(context, row, reportFields, formulaSourceFields, options = {}) {
  const entries = []
  for (const field of reportFields || []) {
    const key = field.exportKey || field.code
    const value = field.formulaEnabled
      ? await evaluateAttendanceReportFormulaField(context, row, field, formulaSourceFields, {
          rawAliasesAllowed: options.rawAliasesAllowed,
        })
      : getAttendanceRecordReportFieldValue(row, field.code)
    entries.push([key, value])
  }
  return Object.fromEntries(entries)
}

function resolveAttendanceSummaryFormulaFields(items) {
  const sourceItems = Array.isArray(items) ? items : []
  return sourceItems
    .filter(field => (
      field
      && field.code
      && field.enabled !== false
      && field.reportVisible !== false
      && field.formulaEnabled === true
      && normalizeAttendanceReportFormulaScope(field.formulaScope) === 'summary'
    ))
    .map(field => ({
      code: field.code,
      name: field.name || field.code,
      unit: field.unit || 'text',
      sortOrder: Number(field.sortOrder) || 0,
      formulaEnabled: true,
      formulaExpression: field.formulaExpression || '',
      formulaScope: 'summary',
      formulaOutputType: normalizeAttendanceReportFormulaOutputType(field.formulaOutputType, field.unit),
      formulaValid: field.formulaValid !== false,
      formulaError: field.formulaError || null,
      formulaReferences: Array.isArray(field.formulaReferences) ? field.formulaReferences : [],
    }))
    .sort((left, right) => {
      if (left.sortOrder !== right.sortOrder) return left.sortOrder - right.sortOrder
      return left.code.localeCompare(right.code)
    })
}

function attendanceSummaryNumber(summary, key) {
  const parsed = Number(summary?.[key] ?? 0)
  return Number.isFinite(parsed) ? parsed : 0
}

function buildAttendanceSummaryFormulaValueMap(summary) {
  const totalDays = attendanceSummaryNumber(summary, 'total_days')
  const absentDays = attendanceSummaryNumber(summary, 'absent_days')
  const lateDays = attendanceSummaryNumber(summary, 'late_days')
  const lateEarlyDays = attendanceSummaryNumber(summary, 'late_early_days')
  const earlyLeaveDays = attendanceSummaryNumber(summary, 'early_leave_days')
  return {
    total_days: totalDays,
    total_minutes: attendanceSummaryNumber(summary, 'total_minutes'),
    total_late_minutes: attendanceSummaryNumber(summary, 'total_late_minutes'),
    total_early_leave_minutes: attendanceSummaryNumber(summary, 'total_early_leave_minutes'),
    normal_days: attendanceSummaryNumber(summary, 'normal_days'),
    late_days: lateDays,
    early_leave_days: earlyLeaveDays,
    late_early_days: lateEarlyDays,
    partial_days: attendanceSummaryNumber(summary, 'partial_days'),
    absent_days: absentDays,
    adjusted_days: attendanceSummaryNumber(summary, 'adjusted_days'),
    off_days: attendanceSummaryNumber(summary, 'off_days'),
    leave_minutes: attendanceSummaryNumber(summary, 'leave_minutes'),
    overtime_minutes: attendanceSummaryNumber(summary, 'overtime_minutes'),
    expected_attendance_days: totalDays,
    attendance_days: Math.max(0, totalDays - absentDays),
    rest_days: attendanceSummaryNumber(summary, 'off_days'),
    work_duration: attendanceSummaryNumber(summary, 'total_minutes'),
    late_count: lateDays + lateEarlyDays,
    late_duration: attendanceSummaryNumber(summary, 'total_late_minutes'),
    early_leave_count: earlyLeaveDays + lateEarlyDays,
    early_leave_duration: attendanceSummaryNumber(summary, 'total_early_leave_minutes'),
    absenteeism_days: absentDays,
    leave_duration: attendanceSummaryNumber(summary, 'leave_minutes'),
    overtime_approval_duration: attendanceSummaryNumber(summary, 'overtime_minutes'),
    workday_overtime_duration: attendanceSummaryNumber(summary, 'workday_overtime_minutes'),
    restday_overtime_duration: attendanceSummaryNumber(summary, 'restday_overtime_minutes'),
    holiday_overtime_duration: attendanceSummaryNumber(summary, 'holiday_overtime_minutes'),
  }
}

async function evaluateAttendanceSummaryFormulaField(context, summary, field) {
  if (!field?.formulaEnabled) return ''
  if (field.formulaValid === false) return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  const values = buildAttendanceSummaryFormulaValueMap(summary)
  const expression = resolveAttendanceReportFormulaExpression(field.formulaExpression, values)
  const formulaApi = context?.api?.formula
  if (!formulaApi?.calculateFormula) return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE

  try {
    const result = await Promise.resolve(formulaApi.calculateFormula(expression))
    return formatAttendanceReportFormulaValue(result, field.formulaOutputType)
  } catch {
    return ATTENDANCE_REPORT_FORMULA_ERROR_VALUE
  }
}

async function buildAttendanceSummaryFormulaValues(context, summary, formulaFields) {
  const entries = []
  for (const field of formulaFields || []) {
    entries.push([field.code, await evaluateAttendanceSummaryFormulaField(context, summary, field)])
  }
  return Object.fromEntries(entries)
}

async function loadAttendanceSummaryFormulaFields(context, orgId, logger, options = {}) {
  const catalog = await buildAttendanceReportFieldCatalogResponse(context, orgId, logger, {
    provision: false,
    rawAliasesAllowed: options.rawAliasesAllowed,
  })
  return resolveAttendanceSummaryFormulaFields(catalog.items)
}

async function enrichAttendanceSummaryWithFormulaValues(context, summary, formulaFields) {
  const formulaValues = await buildAttendanceSummaryFormulaValues(context, summary, formulaFields)
  if (Object.keys(formulaValues).length === 0) return summary
  return {
    ...summary,
    formula_values: formulaValues,
    formula_fields: formulaFields.map(field => ({
      code: field.code,
      name: field.name,
      unit: field.unit,
      formulaOutputType: field.formulaOutputType,
      formulaValid: field.formulaValid,
      formulaError: field.formulaError,
      formulaReferences: field.formulaReferences,
    })),
  }
}

function normalizeAttendancePayrollSummaryFieldTemplateConfig(config) {
  const payload = normalizeMetadata(config)
  const rawFields = firstDefinedValue(
    payload.summaryFieldCodes,
    payload.summaryFields,
    payload.payrollSummaryFieldCodes,
    payload.payrollSummaryFields,
    payload.summary_field_codes,
    payload.summary_fields,
  )
  if (!Array.isArray(rawFields)) {
    return { configured: false, fieldCodes: [] }
  }
  const seen = new Set()
  const fieldCodes = []
  for (const item of rawFields) {
    const source = item && typeof item === 'object'
      ? firstDefinedValue(item.code, item.fieldCode, item.field_code, item.metric)
      : item
    if (item && typeof item === 'object' && item.enabled === false) continue
    const code = typeof source === 'string' ? source.trim() : ''
    if (!code || seen.has(code)) continue
    seen.add(code)
    fieldCodes.push(code)
  }
  return { configured: true, fieldCodes }
}

function getAttendancePayrollSummaryFieldValue(summary, code) {
  if (!summary || !code) return ''
  const formulaValues = summary.formula_values && typeof summary.formula_values === 'object'
    ? summary.formula_values
    : {}
  if (Object.prototype.hasOwnProperty.call(formulaValues, code)) return formulaValues[code]
  if (Object.prototype.hasOwnProperty.call(summary, code)) return summary[code]
  const valueMap = buildAttendanceSummaryFormulaValueMap(summary)
  if (Object.prototype.hasOwnProperty.call(valueMap, code)) return valueMap[code]
  return ''
}

function buildAttendancePayrollSummaryFieldTemplate(summary, formulaFields, config) {
  const normalized = normalizeAttendancePayrollSummaryFieldTemplateConfig(config)
  const formulaFieldMap = new Map(
    (Array.isArray(formulaFields) ? formulaFields : [])
      .filter(field => field?.code)
      .map(field => [field.code, field])
  )
  const requestedCodes = normalized.configured
    ? normalized.fieldCodes
    : [
        ...ATTENDANCE_PAYROLL_SUMMARY_DEFAULT_FIELD_CODES,
        ...[...formulaFieldMap.keys()].filter(code => !ATTENDANCE_PAYROLL_SUMMARY_DEFAULT_FIELD_CODES.includes(code)),
      ]
  const fields = []
  const droppedFieldCodes = []
  for (const code of requestedCodes) {
    const formulaField = formulaFieldMap.get(code)
    if (formulaField) {
      fields.push({
        code,
        name: formulaField.name || code,
        unit: formulaField.unit || 'text',
        formulaOutputType: formulaField.formulaOutputType || 'text',
        formulaEnabled: true,
        value: getAttendancePayrollSummaryFieldValue(summary, code),
      })
      continue
    }
    const baseField = ATTENDANCE_SUMMARY_FORMULA_SOURCE_FIELD_MAP.get(code)
    if (baseField) {
      fields.push({
        code,
        name: baseField.name || code,
        unit: baseField.unit || 'number',
        formulaOutputType: normalizeAttendanceReportFormulaOutputType(null, baseField.unit),
        formulaEnabled: false,
        value: getAttendancePayrollSummaryFieldValue(summary, code),
      })
      continue
    }
    droppedFieldCodes.push(code)
  }
  return {
    configured: normalized.configured,
    fieldCodes: fields.map(field => field.code),
    fields,
    droppedFieldCodes,
  }
}

async function loadPayrollTemplateForCycle(db, orgId, cycle) {
  if (!cycle?.templateId) return null
  const rows = await db.query(
    'SELECT * FROM attendance_payroll_templates WHERE id = $1 AND org_id = $2',
    [cycle.templateId, orgId]
  )
  return rows.length ? mapPayrollTemplateRow(rows[0]) : null
}

function findImportProfile(profileId) {
  if (!profileId) return null
  return IMPORT_MAPPING_PROFILES.find((profile) => profile.id === profileId) ?? null
}

function uniqueImportTemplateStrings(values) {
  if (!Array.isArray(values)) return []
  const normalized = values
    .map((value) => String(value ?? '').trim())
    .filter(Boolean)
  return Array.from(new Set(normalized))
}

function extractImportTemplateColumns(columns) {
  if (!Array.isArray(columns)) return []
  const values = []
  for (const column of columns) {
    if (typeof column === 'string') {
      const text = column.trim()
      if (text) values.push(text)
      continue
    }
    if (!column || typeof column !== 'object') continue
    const candidate = column.header
      ?? column.sourceField
      ?? column.source
      ?? column.name
      ?? column.field
      ?? column.key
      ?? column.targetField
      ?? column.label
    if (typeof candidate === 'string') {
      const text = candidate.trim()
      if (text) values.push(text)
    }
  }
  return Array.from(new Set(values))
}

function getDefaultImportTemplateProfile() {
  return findImportProfile(DEFAULT_IMPORT_TEMPLATE_PROFILE_ID)
    ?? IMPORT_MAPPING_PROFILES[0]
    ?? null
}

function resolveImportTemplateProfile(profileId) {
  const normalized = typeof profileId === 'string' ? profileId.trim() : ''
  if (!normalized) return { profile: getDefaultImportTemplateProfile(), error: null }
  const profile = findImportProfile(normalized)
  if (profile) return { profile, error: null }
  return {
    profile: null,
    error: `Unknown import template profile: ${normalized}`,
  }
}

function resolveImportTemplateColumns(profile) {
  const templateColumns = uniqueImportTemplateStrings(profile?.templateColumns)
  if (templateColumns.length > 0) return templateColumns
  return extractImportTemplateColumns(profile?.mapping?.columns)
}

function resolveImportTemplateRequiredFields(profile) {
  return uniqueImportTemplateStrings(profile?.requiredFields)
}

function buildImportTemplatePayloadExample(profile) {
  const columns = resolveImportTemplateColumns(profile)
  const requiredFields = resolveImportTemplateRequiredFields(profile)
  const source = typeof profile?.source === 'string' && profile.source.trim()
    ? profile.source.trim()
    : 'dingtalk_csv'

  return {
    source,
    mode: 'override',
    columns,
    requiredFields,
    // Keep the template payload valid out-of-the-box: ruleSetId is optional.
    userMapKeyField: typeof profile?.userMapKeyField === 'string' && profile.userMapKeyField.trim()
      ? profile.userMapKeyField.trim()
      : '工号',
    userMapSourceFields: uniqueImportTemplateStrings(profile?.userMapSourceFields).length > 0
      ? uniqueImportTemplateStrings(profile.userMapSourceFields)
      : ['empNo', '工号', '姓名'],
    userMap: {},
    entries: [],
  }
}

function buildAttendanceImportTemplateData(profile) {
  const query = profile?.id ? `?profileId=${encodeURIComponent(profile.id)}` : ''
  return {
    source: typeof profile?.source === 'string' && profile.source.trim()
      ? profile.source.trim()
      : 'dingtalk',
    defaultProfileId: profile?.id ?? null,
    csvTemplateUrl: `/api/attendance/import/template.csv${query}`,
    csvTemplateFilename: buildImportTemplateFilename(profile),
    mapping: {
      columns: IMPORT_MAPPING_COLUMNS,
    },
    mappingProfiles: IMPORT_MAPPING_PROFILES,
    payloadExample: buildImportTemplatePayloadExample(profile),
  }
}

function escapeImportTemplateCsvCell(value) {
  const text = String(value ?? '')
  if (/[",\n\r]/.test(text)) {
    return `"${text.replace(/"/g, '""')}"`
  }
  return text
}

function buildImportTemplateCsv(profile) {
  const columns = resolveImportTemplateColumns(profile)
  if (columns.length === 0) return ''
  const sampleRow = Array.isArray(profile?.templateSampleRow) ? profile.templateSampleRow : []
  const normalizedSampleRow = columns.map((_, index) => sampleRow[index] ?? '')
  const header = columns.map(escapeImportTemplateCsvCell).join(',')
  const row = normalizedSampleRow.map(escapeImportTemplateCsvCell).join(',')
  return `${header}\n${row}\n`
}

function buildImportTemplateFilename(profile) {
  const seed = String(profile?.id || profile?.source || 'attendance')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '-')
    .replace(/^-+|-+$/g, '')
  return `attendance-import-template-${seed || 'attendance'}.csv`
}

function normalizeImportPayload(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return payload ?? {}
  const next = { ...payload }
  if (next.csvFileId === undefined) next.csvFileId = next.fileId ?? next.csv_file_id
  if (next.mappingProfileId === undefined) next.mappingProfileId = next.profileId ?? next.mapping_profile_id
  if (next.userId === undefined) next.userId = next.user_id
  if (next.orgId === undefined) next.orgId = next.org_id
  if (next.commitToken === undefined) next.commitToken = next.commit_token
  if (next.previewLimit === undefined) next.previewLimit = next.preview_limit
  if (next.returnItems === undefined) next.returnItems = next.return_items
  if (next.itemsLimit === undefined) next.itemsLimit = next.items_limit
  if (next.ruleSetId === undefined) next.ruleSetId = next.rule_set_id
  if (next.userMap === undefined) next.userMap = next.user_map
  if (next.userMapKeyField === undefined) next.userMapKeyField = next.user_map_key_field
  if (next.userMapSourceFields === undefined) next.userMapSourceFields = next.user_map_source_fields
  if (next.groupSync === undefined) next.groupSync = next.group_sync
  if (next.batchMeta === undefined) next.batchMeta = next.batch_meta
  if (next.csvText === undefined) next.csvText = next.csv_text
  if (next.csvOptions === undefined) next.csvOptions = next.csv_options
  if (next.idempotencyKey === undefined) next.idempotencyKey = next.idempotency_key
  return next
}

function resolveImportProfileForPayload(payload) {
  const profile = findImportProfile(payload?.mappingProfileId)
  if (profile) return profile
  const source = typeof payload?.source === 'string' ? payload.source.trim() : ''
  const hasCsvInput = (
    typeof payload?.csvFileId === 'string' && payload.csvFileId.trim()
  ) || (
    typeof payload?.csvText === 'string' && payload.csvText.trim()
  )
  if (hasCsvInput && (!source || source === 'csv' || source === 'dingtalk_csv')) {
    return getDefaultImportTemplateProfile()
  }
  return null
}

const IMPORT_COMMIT_TOKEN_TTL_MS = 10 * 60 * 1000
const requireImportCommitToken = process.env.ATTENDANCE_IMPORT_REQUIRE_TOKEN === '1'
const importCommitTokens = new Map()

async function pruneImportCommitTokensDb(db) {
  if (!db) return
  try {
    await db.query('DELETE FROM attendance_import_tokens WHERE expires_at <= now()')
  } catch (error) {
    if (isDatabaseSchemaError(error)) return
  }
}

function pruneImportCommitTokens() {
  const now = Date.now()
  for (const [token, entry] of importCommitTokens.entries()) {
    if (!entry || entry.expiresAt <= now) {
      importCommitTokens.delete(token)
    }
  }
}

async function createImportCommitToken({ db, orgId, userId }) {
  pruneImportCommitTokens()
  const token = randomUUID()
  const expiresAt = Date.now() + IMPORT_COMMIT_TOKEN_TTL_MS

  // Production mode: tokens must be shareable across multiple backend instances.
  // When enforcement is enabled, require DB persistence and fail fast if the table is missing.
  if (requireImportCommitToken) {
    if (!db) {
      throw new HttpError(
        503,
        'DB_NOT_READY',
        'Database connection is required to issue import commit tokens.',
      )
    }
    await pruneImportCommitTokensDb(db)
    try {
      await db.query(
        `INSERT INTO attendance_import_tokens
         (token, org_id, user_id, expires_at, created_at)
         VALUES ($1, $2, $3, $4, now())`,
        [token, orgId, userId, new Date(expiresAt)]
      )
    } catch (error) {
      if (isDatabaseSchemaError(error)) {
        throw new HttpError(
          503,
          'DB_NOT_READY',
          'Attendance import token table missing. Run migrations before enabling token enforcement.',
        )
      }
      throw error
    }

    importCommitTokens.set(token, { orgId, userId, expiresAt })
    return { token, expiresAt }
  }

  importCommitTokens.set(token, { orgId, userId, expiresAt })
  if (db) {
    await pruneImportCommitTokensDb(db)
    try {
      await db.query(
        `INSERT INTO attendance_import_tokens
         (token, org_id, user_id, expires_at, created_at)
         VALUES ($1, $2, $3, $4, now())`,
        [token, orgId, userId, new Date(expiresAt)]
      )
    } catch (error) {
      if (!isDatabaseSchemaError(error)) {
        throw error
      }
    }
  }
  return { token, expiresAt }
}

async function consumeImportCommitToken(token, { db, orgId, userId }) {
  pruneImportCommitTokens()
  const entry = importCommitTokens.get(token)
  if (entry) {
    if (entry.orgId !== orgId) return false
    if (entry.userId !== userId) return false
    if (entry.expiresAt <= Date.now()) {
      importCommitTokens.delete(token)
      return false
    }
    importCommitTokens.delete(token)
    if (db) {
      try {
        await db.query('DELETE FROM attendance_import_tokens WHERE token = $1', [token])
      } catch (error) {
        if (isDatabaseSchemaError(error) && requireImportCommitToken) {
          throw new HttpError(
            503,
            'DB_NOT_READY',
            'Attendance import token table missing. Run migrations before enabling token enforcement.',
          )
        }
        if (!isDatabaseSchemaError(error)) {
          throw error
        }
      }
    }
    return true
  }

  if (!db) {
    if (requireImportCommitToken) {
      throw new HttpError(
        503,
        'DB_NOT_READY',
        'Database connection is required to validate import commit tokens.',
      )
    }
    return false
  }
  await pruneImportCommitTokensDb(db)
  try {
    const rows = await db.query(
      'SELECT token, org_id, user_id, expires_at FROM attendance_import_tokens WHERE token = $1',
      [token]
    )
    if (!rows.length) return false
    const row = rows[0]
    if (row.org_id !== orgId || row.user_id !== userId) return false
    if (new Date(row.expires_at).getTime() <= Date.now()) {
      await db.query('DELETE FROM attendance_import_tokens WHERE token = $1', [token])
      return false
    }
    await db.query('DELETE FROM attendance_import_tokens WHERE token = $1', [token])
    return true
  } catch (error) {
    if (isDatabaseSchemaError(error)) {
      if (requireImportCommitToken) {
        throw new HttpError(
          503,
          'DB_NOT_READY',
          'Attendance import token table missing. Run migrations before enabling token enforcement.',
        )
      }
      return false
    }
    throw error
  }
}

function ensureStringArray(value) {
  if (!value) return []
  if (Array.isArray(value)) return value.map((item) => String(item)).filter(Boolean)
  if (typeof value === 'string') {
    return value.split(',').map((item) => item.trim()).filter(Boolean)
  }
  return []
}

function ensureNumberArray(value) {
  if (!value) return []
  if (Array.isArray(value)) {
    return value
      .map((item) => parseNumber(item, null))
      .filter((item) => Number.isFinite(item))
  }
  if (typeof value === 'string') {
    return value
      .split(/[\s,]+/)
      .map((item) => parseNumber(item, null))
      .filter((item) => Number.isFinite(item))
  }
  return []
}

const SECRET_PREFIX = 'enc:'
const SECRET_ENCRYPTION_ALGORITHM = 'aes-256-gcm'
const SECRET_KEY_ITERATIONS = 100000
const SECRET_KEY_LENGTH = 32
const SECRET_IV_LENGTH = 16
const SECRET_AUTH_TAG_LENGTH = 16
const DINGTALK_LOG_MASK_QUERY_KEYS = new Set(['access_token', 'appsecret', 'sign', 'timestamp'])

function normalizeTextValue(value) {
  return typeof value === 'string' ? value.trim() : String(value ?? '').trim()
}

function isEncryptedSecretValue(value) {
  return typeof value === 'string' && value.startsWith(SECRET_PREFIX)
}

function getIntegrationSecretKey() {
  const masterKey = process.env.ENCRYPTION_KEY || 'default-key-change-in-production'
  const salt = Buffer.from(process.env.ENCRYPTION_SALT || 'default-salt-change-in-production')
  return crypto.pbkdf2Sync(masterKey, salt, SECRET_KEY_ITERATIONS, SECRET_KEY_LENGTH, 'sha256')
}

function encryptIntegrationSecretValue(plaintext) {
  const iv = crypto.randomBytes(SECRET_IV_LENGTH)
  const cipher = crypto.createCipheriv(SECRET_ENCRYPTION_ALGORITHM, getIntegrationSecretKey(), iv)
  const encrypted = Buffer.concat([cipher.update(String(plaintext ?? ''), 'utf8'), cipher.final()])
  const authTag = cipher.getAuthTag()
  return `${SECRET_PREFIX}${Buffer.concat([iv, authTag, encrypted]).toString('base64')}`
}

function decryptIntegrationSecretValue(value) {
  if (!isEncryptedSecretValue(value)) return String(value ?? '')
  const payload = Buffer.from(value.slice(SECRET_PREFIX.length), 'base64')
  const iv = payload.subarray(0, SECRET_IV_LENGTH)
  const authTag = payload.subarray(SECRET_IV_LENGTH, SECRET_IV_LENGTH + SECRET_AUTH_TAG_LENGTH)
  const encrypted = payload.subarray(SECRET_IV_LENGTH + SECRET_AUTH_TAG_LENGTH)
  const decipher = crypto.createDecipheriv(SECRET_ENCRYPTION_ALGORITHM, getIntegrationSecretKey(), iv)
  decipher.setAuthTag(authTag)
  return Buffer.concat([decipher.update(encrypted), decipher.final()]).toString('utf8')
}

function normalizeStoredIntegrationSecretValue(value) {
  const normalized = normalizeTextValue(value)
  if (!normalized) return ''
  return isEncryptedSecretValue(normalized) ? normalized : encryptIntegrationSecretValue(normalized)
}

function readDingTalkAllowedCorpIds() {
  return Array.from(new Set(
    normalizeTextValue(process.env.DINGTALK_ALLOWED_CORP_IDS)
      .split(/[\s,]+/)
      .map((item) => item.trim())
      .filter(Boolean)
  ))
}

function assertDingTalkCorpAllowed(corpId, { allowEmpty = false, context = 'DingTalk corpId' } = {}) {
  const allowedCorpIds = readDingTalkAllowedCorpIds()
  if (!allowedCorpIds.length) return

  const normalizedCorpId = normalizeTextValue(corpId)
  if (!normalizedCorpId) {
    if (allowEmpty) return
    throw new Error(`${context} is required when DINGTALK_ALLOWED_CORP_IDS is configured`)
  }
  if (allowedCorpIds.includes(normalizedCorpId)) return
  throw new Error(`${context} ${normalizedCorpId} is not allowed by DINGTALK_ALLOWED_CORP_IDS`)
}

function maskDingTalkUrlForLog(url) {
  try {
    const parsed = new URL(url)
    for (const key of DINGTALK_LOG_MASK_QUERY_KEYS) {
      if (parsed.searchParams.has(key)) {
        parsed.searchParams.set(key, '***')
      }
    }
    return parsed.toString()
  } catch {
    return String(url ?? '').replace(/([?&](?:access_token|appsecret|sign|timestamp)=)[^&]+/gi, '$1***')
  }
}

function normalizeIntegrationConfig(config) {
  if (!config || typeof config !== 'object') return {}
  const appSecret = config.appSecret ?? config.appsecret ?? config.app_secret
  return {
    ...config,
    appKey: config.appKey ?? config.appkey ?? config.app_key,
    appSecret: normalizeTextValue(appSecret) ? decryptIntegrationSecretValue(String(appSecret)) : '',
    corpId: config.corpId ?? config.corp_id ?? null,
    baseUrl: config.baseUrl ?? config.base_url ?? 'https://oapi.dingtalk.com',
    userIds: ensureStringArray(config.userIds ?? config.user_ids ?? config.users),
    columnIds: ensureStringArray(config.columnIds ?? config.column_id_list ?? config.columns).map((id) => String(id)),
    columns: Array.isArray(config.columns) ? config.columns : [],
    mappingProfileId: config.mappingProfileId ?? config.mapping_profile_id ?? null,
    userMapKeyField: config.userMapKeyField ?? config.user_map_key_field ?? null,
    userMapSourceFields: Array.isArray(config.userMapSourceFields) ? config.userMapSourceFields : undefined,
    userMap: config.userMap ?? config.user_map ?? undefined,
    timezone: config.timezone ?? 'Asia/Shanghai',
    source: config.source ?? 'dingtalk_api',
  }
}

function normalizeIntegrationConfigForStorage(config) {
  const normalized = normalizeIntegrationConfig(config)
  return {
    ...normalized,
    corpId: normalizeTextValue(normalized.corpId) || null,
    appSecret: normalized.appSecret ? normalizeStoredIntegrationSecretValue(normalized.appSecret) : '',
  }
}

const ATTENDANCE_DINGTALK_HTTP_TIMEOUT_MS = (() => {
  const raw = Number(process.env.ATTENDANCE_DINGTALK_HTTP_TIMEOUT_MS ?? 10000)
  return Number.isFinite(raw) && raw > 0 ? Math.floor(raw) : 10000
})()

const ATTENDANCE_DINGTALK_HTTP_MAX_ATTEMPTS = (() => {
  const raw = Number(process.env.ATTENDANCE_DINGTALK_HTTP_MAX_ATTEMPTS ?? 3)
  return Number.isFinite(raw) && raw >= 1 ? Math.min(Math.floor(raw), 6) : 3
})()

const ATTENDANCE_DINGTALK_HTTP_RETRY_DELAY_MS = (() => {
  const raw = Number(process.env.ATTENDANCE_DINGTALK_HTTP_RETRY_DELAY_MS ?? 750)
  return Number.isFinite(raw) && raw >= 50 ? Math.floor(raw) : 750
})()

const dingTalkTokenCache = new Map()

function sleepMs(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

function shouldRetryDingTalkRequest({ status, errcode }) {
  if (status === 408 || status === 429 || status >= 500) return true
  return errcode === 88 || errcode === 60020
}

function calculateDingTalkRetryDelay(attempt) {
  const exponential = ATTENDANCE_DINGTALK_HTTP_RETRY_DELAY_MS * Math.pow(2, Math.max(0, attempt - 1))
  const jitter = Math.floor(Math.random() * Math.max(50, exponential * 0.2))
  return Math.min(5000, exponential + jitter)
}

async function readDingTalkJsonSafely(response) {
  try {
    return await response.json()
  } catch {
    return null
  }
}

async function requestDingTalkJsonWithRetry({ url, method = 'GET', headers, body, timeoutMs = ATTENDANCE_DINGTALK_HTTP_TIMEOUT_MS }) {
  let lastError = null
  const maskedUrl = maskDingTalkUrlForLog(url)
  for (let attempt = 1; attempt <= ATTENDANCE_DINGTALK_HTTP_MAX_ATTEMPTS; attempt += 1) {
    try {
      const response = await fetch(url, {
        method,
        headers,
        body,
        signal: AbortSignal.timeout(timeoutMs),
      })
      const data = await readDingTalkJsonSafely(response)
      if (!response.ok || data?.errcode) {
        const message = data?.errmsg || `HTTP ${response.status}`
        if (attempt < ATTENDANCE_DINGTALK_HTTP_MAX_ATTEMPTS && shouldRetryDingTalkRequest({ status: response.status, errcode: data?.errcode })) {
          const delay = calculateDingTalkRetryDelay(attempt)
          logger.warn('Retrying DingTalk request', { url: maskedUrl, attempt, delay, status: response.status, errcode: data?.errcode, message })
          await sleepMs(delay)
          continue
        }
        throw new Error(message || 'DingTalk request failed')
      }
      return data ?? {}
    } catch (error) {
      lastError = error
      if (attempt >= ATTENDANCE_DINGTALK_HTTP_MAX_ATTEMPTS) break
      const delay = calculateDingTalkRetryDelay(attempt)
      logger.warn('DingTalk request attempt failed', { url: maskedUrl, attempt, delay, error: error?.message || String(error) })
      await sleepMs(delay)
    }
  }
  throw lastError || new Error('DingTalk request failed')
}

async function fetchDingTalkAccessToken({ appKey, appSecret, baseUrl }) {
  if (!appKey || !appSecret) {
    throw new Error('DingTalk appKey/appSecret required')
  }
  const cacheKey = `${baseUrl}|${appKey}|${appSecret}`
  const cached = dingTalkTokenCache.get(cacheKey)
  if (cached?.token && Number.isFinite(cached.expiresAt) && cached.expiresAt > Date.now()) {
    return cached.token
  }
  const tokenUrl = `${baseUrl}/gettoken?appkey=${encodeURIComponent(appKey)}&appsecret=${encodeURIComponent(appSecret)}`
  const data = await requestDingTalkJsonWithRetry({ url: tokenUrl })
  const accessToken = data?.access_token
  const expiresInSeconds = Number(data?.expires_in ?? 7200)
  const safeTtlMs = Number.isFinite(expiresInSeconds) && expiresInSeconds > 300
    ? (expiresInSeconds - 300) * 1000
    : 60 * 60 * 1000
  dingTalkTokenCache.set(cacheKey, {
    token: accessToken,
    expiresAt: Date.now() + safeTtlMs,
  })
  return accessToken
}

function normalizeDingTalkDateRange(value, fallback) {
  if (!value) return fallback
  const text = String(value).trim()
  if (!text) return fallback
  if (/^\d{4}-\d{2}-\d{2}$/.test(text)) return `${text} 00:00:00`
  return text
}

async function fetchDingTalkColumnValues({ baseUrl, accessToken, userId, columnIds, fromDate, toDate }) {
  const url = `${baseUrl}/topapi/attendance/getcolumnval?access_token=${encodeURIComponent(accessToken)}`
  const body = {
    userid: userId,
    column_id_list: Array.isArray(columnIds) ? columnIds.join(',') : String(columnIds ?? ''),
    from_date: fromDate,
    to_date: toDate,
  }
  const data = await requestDingTalkJsonWithRetry({
    url,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  })
  return data?.result ?? {}
}

class HttpError extends Error {
  constructor(status, code, message, details = null) {
    super(message)
    this.status = status
    this.code = code
    if (Array.isArray(details) && details.length > 0) {
      this.details = details
    }
  }
}

function formatZodValidationDetails(error) {
  const issues = Array.isArray(error?.issues) ? error.issues : []
  return issues.map((issue) => ({
    field: Array.isArray(issue?.path) && issue.path.length > 0 ? issue.path.join('.') : 'body',
    message: issue?.message || 'Invalid value',
  }))
}

function singleValidationDetail(field, message) {
  return [{ field, message }]
}

function validationErrorBody(message, details = null) {
  return {
    ok: false,
    error: {
      code: 'VALIDATION_ERROR',
      message,
      ...(Array.isArray(details) && details.length > 0 ? { details } : {}),
    },
  }
}

function formatEngineConfigError(error) {
  const details = Array.isArray(error?.details) ? error.details : null
  const first = details && details.length > 0 ? details[0] : null
  const message = first
    ? `Invalid engine config: ${first.path || 'config'} ${first.message}`
    : (error?.message || 'Invalid engine config')
  return { message, details }
}

function isDatabaseSchemaError(error) {
  if (error?.code === '42P01') return true
  if (error?.code === '42703') return true
  if (typeof error?.message === 'string') {
    const msg = error.message.toLowerCase()
    if ((msg.includes('relation') || msg.includes('table')) && msg.includes('does not exist')) {
      return true
    }
    if (msg.includes('column') && msg.includes('does not exist')) {
      return true
    }
  }
  return false
}

function parsePagination(query, options = {}) {
  const {
    defaultPage = 1,
    defaultPageSize = 50,
    maxPageSize = 200,
    minPageSize = 1,
  } = options

  const page = Math.max(parseInt(String(query.page || defaultPage), 10), 1)
  const pageSize = Math.min(
    Math.max(parseInt(String(query.pageSize || defaultPageSize), 10), minPageSize),
    maxPageSize,
  )
  const offset = (page - 1) * pageSize

  return { page, pageSize, offset }
}

function parseBoolean(value, fallback = false) {
  if (typeof value === 'boolean') return value
  if (typeof value !== 'string') return fallback
  const normalized = value.trim().toLowerCase()
  if (normalized === 'true' || normalized === '1' || normalized === 'yes') return true
  if (normalized === 'false' || normalized === '0' || normalized === 'no') return false
  return fallback
}

function parseNumber(value, fallback) {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return fallback
  return parsed
}

function getUserId(req) {
  const user = req.user
  const headerUserId = req.headers['x-user-id']
  const header = Array.isArray(headerUserId) ? headerUserId[0] : headerUserId
  const raw = user?.id ?? user?.sub ?? user?.userId ?? header
  if (typeof raw === 'string' && raw.trim().length > 0) return raw
  if (typeof raw === 'number' && Number.isFinite(raw)) return String(raw)
  return null
}

function getOrgId(req) {
  const user = req.user
  const headerOrg = req.headers['x-org-id']
  const header = Array.isArray(headerOrg) ? headerOrg[0] : headerOrg
  const raw = req.body?.orgId ?? req.query?.orgId ?? user?.orgId ?? user?.workspaceId ?? header
  if (typeof raw === 'string' && raw.trim().length > 0) return raw
  if (typeof raw === 'number' && Number.isFinite(raw)) return String(raw)
  return DEFAULT_ORG_ID
}

function getUserLabel(req, fallback) {
  const user = req.user
  if (typeof user?.name === 'string' && user.name.trim().length > 0) return user.name
  if (typeof user?.email === 'string' && user.email.trim().length > 0) return user.email
  return fallback
}

function getClientIp(req) {
  const forwarded = req.headers['x-forwarded-for']
  const header = Array.isArray(forwarded) ? forwarded[0] : forwarded
  const raw = header ? String(header).split(',')[0]?.trim() : req.ip
  if (!raw) return ''
  return raw.startsWith('::ffff:') ? raw.slice(7) : raw
}

function isIpAllowed(ip, allowlist) {
  if (!allowlist || allowlist.length === 0) return true
  const normalized = ip.trim()
  return allowlist.some((entry) => {
    if (!entry) return false
    const rule = entry.trim()
    if (!rule) return false
    if (rule.endsWith('*')) {
      const prefix = rule.slice(0, -1)
      return normalized.startsWith(prefix)
    }
    if (rule.includes('/')) {
      const [base, mask] = rule.split('/')
      if (mask === '32') return normalized === base
      if (mask === '24') {
        const prefix = base.split('.').slice(0, 3).join('.') + '.'
        return normalized.startsWith(prefix)
      }
      return normalized === base
    }
    return normalized === rule
  })
}

function toRadians(deg) {
  return (deg * Math.PI) / 180
}

function distanceInMeters(a, b) {
  const earthRadius = 6371000
  const lat1 = toRadians(a.lat)
  const lat2 = toRadians(b.lat)
  const dLat = toRadians(b.lat - a.lat)
  const dLng = toRadians(b.lng - a.lng)
  const sinLat = Math.sin(dLat / 2)
  const sinLng = Math.sin(dLng / 2)
  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLng * sinLng
  return 2 * earthRadius * Math.asin(Math.min(1, Math.sqrt(h)))
}

function isGeoAllowed(location, fence) {
  if (!fence) return true
  if (!location || typeof location.lat !== 'number' || typeof location.lng !== 'number') {
    return false
  }
  const radius = Number(fence.radiusMeters ?? 0)
  if (!Number.isFinite(radius) || radius <= 0) return false
  const dist = distanceInMeters({ lat: location.lat, lng: location.lng }, fence)
  return dist <= radius
}

function parseDateInput(value) {
  if (!value) return null
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return null
  return date
}

function normalizeDateOnlyStrict(value) {
  if (typeof value !== 'string') return null
  const normalized = value.trim()
  if (!/^\d{4}-\d{2}-\d{2}$/.test(normalized)) return null
  const date = new Date(`${normalized}T00:00:00.000Z`)
  if (Number.isNaN(date.getTime())) return null
  return date.toISOString().slice(0, 10) === normalized ? normalized : null
}

function normalizeDateOnlyValue(value) {
  if (value instanceof Date) {
    if (Number.isNaN(value.getTime())) return null
    const localMidnight =
      value.getHours() === 0
      && value.getMinutes() === 0
      && value.getSeconds() === 0
      && value.getMilliseconds() === 0
    const utcMidnight =
      value.getUTCHours() === 0
      && value.getUTCMinutes() === 0
      && value.getUTCSeconds() === 0
      && value.getUTCMilliseconds() === 0
    if (localMidnight && !utcMidnight) {
      return [
        String(value.getFullYear()).padStart(4, '0'),
        String(value.getMonth() + 1).padStart(2, '0'),
        String(value.getDate()).padStart(2, '0'),
      ].join('-')
    }
    return value.toISOString().slice(0, 10)
  }
  return normalizeDateOnlyStrict(value)
}

function normalizeUuidString(value) {
  if (typeof value !== 'string') return null
  const normalized = value.trim()
  if (!normalized) return null
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(normalized)
    ? normalized
    : null
}

async function validateRotationShiftSequenceIds(db, orgId, shiftSequence) {
  const targetOrg = orgId || DEFAULT_ORG_ID
  const normalizedSequence = normalizeStringArray(shiftSequence)
  if (normalizedSequence.length === 0) {
    return { shiftSequence: [], invalidReferences: [] }
  }

  const normalizedIds = normalizedSequence.map((shiftRef) => normalizeUuidString(shiftRef))
  const malformedReferences = normalizedSequence.filter((_, index) => !normalizedIds[index])
  if (malformedReferences.length > 0) {
    return { shiftSequence: normalizedSequence, invalidReferences: malformedReferences }
  }

  const rows = await db.query(
    'SELECT id FROM attendance_shifts WHERE org_id = $1 AND id = ANY($2::uuid[])',
    [targetOrg, normalizedIds]
  )
  const existingIds = new Set(
    rows
      .map((row) => normalizeUuidString(row?.id))
      .filter(Boolean)
  )
  const missingReferences = normalizedSequence.filter((shiftId) => !existingIds.has(shiftId))
  if (missingReferences.length > 0) {
    return { shiftSequence: normalizedSequence, invalidReferences: missingReferences }
  }

  return {
    shiftSequence: normalizedIds,
    invalidReferences: [],
  }
}

function respondInvalidUuid(res, fieldName = 'id') {
  res.status(400).json({ ok: false, error: { code: 'VALIDATION_ERROR', message: `${fieldName} must be a UUID` } })
}

function isValidTimeZoneIdentifier(value) {
  const zone = typeof value === 'string' ? value.trim() : ''
  if (!zone) return false
  try {
    new Intl.DateTimeFormat('en-US', { timeZone: zone }).format(new Date())
    return true
  } catch {
    return false
  }
}

function resolveExplicitTimeZoneOrThrow(value, fallback, fieldName = 'timezone') {
  if (value === undefined || value === null) return fallback
  const zone = typeof value === 'string' ? value.trim() : ''
  if (!zone) {
    throw new HttpError(400, 'VALIDATION_ERROR', `${fieldName} is required`)
  }
  if (!isValidTimeZoneIdentifier(zone)) {
    throw new HttpError(400, 'VALIDATION_ERROR', `${fieldName} must be a valid IANA time zone`)
  }
  return zone
}

function normalizeSafeDisplayName(fieldName, value) {
  const normalized = typeof value === 'string' ? value.trim() : ''
  if (!normalized) {
    throw new HttpError(400, 'VALIDATION_ERROR', `${fieldName} is required`)
  }
  if (
    /[<>]/.test(normalized)
    || /<\/?[a-z][^>]*>/i.test(normalized)
    || /["'`]/.test(normalized)
    || /\bjavascript\s*:/i.test(normalized)
    || /\bon[a-z]+\s*=/i.test(normalized)
  ) {
    throw new HttpError(400, 'VALIDATION_ERROR', `${fieldName} contains unsafe characters`)
  }
  return normalized
}

function resolveAttendanceDateRange(fromValue, toValue, fallbackDays = 30) {
  const fallbackFrom = new Date(Date.now() - 1000 * 60 * 60 * 24 * fallbackDays).toISOString().slice(0, 10)
  const fallbackTo = new Date().toISOString().slice(0, 10)
  const from = fromValue === undefined ? fallbackFrom : normalizeDateOnlyStrict(fromValue)
  if (fromValue !== undefined && !from) {
    return { ok: false, message: 'Invalid "from" date. Use YYYY-MM-DD.' }
  }
  const to = toValue === undefined ? fallbackTo : normalizeDateOnlyStrict(toValue)
  if (toValue !== undefined && !to) {
    return { ok: false, message: 'Invalid "to" date. Use YYYY-MM-DD.' }
  }
  if (from > to) {
    return { ok: false, message: '"from" date must be on or before "to" date.' }
  }
  return { ok: true, from, to }
}

function normalizeOptionalText(value) {
  if (value === null || value === undefined) return null
  const normalized = String(value).trim()
  return normalized || null
}

function normalizeDuplicateRequestTimestamp(value) {
  const parsed = value instanceof Date ? value : parseDateInput(value)
  return parsed ? parsed.toISOString() : null
}

function buildAttendanceRequestFingerprint(input) {
  return {
    requestedInAt: normalizeDuplicateRequestTimestamp(input.requestedInAt),
    requestedOutAt: normalizeDuplicateRequestTimestamp(input.requestedOutAt),
    reason: normalizeOptionalText(input.reason),
    minutes: Number.isFinite(Number(input.minutes)) ? Number(input.minutes) : null,
    attachmentUrl: normalizeOptionalText(input.attachmentUrl),
    leaveTypeId: normalizeOptionalText(input.leaveTypeId),
    leaveTypeCode: normalizeOptionalText(input.leaveTypeCode),
    overtimeRuleId: normalizeOptionalText(input.overtimeRuleId),
    overtimeRuleName: normalizeOptionalText(input.overtimeRuleName),
  }
}

function matchesAttendanceRequestFingerprint(row, fingerprint) {
  const metadata = normalizeMetadata(row.metadata)
  const rowFingerprint = buildAttendanceRequestFingerprint({
    requestedInAt: row.requested_in_at,
    requestedOutAt: row.requested_out_at,
    reason: row.reason,
    minutes: metadata.minutes,
    attachmentUrl: metadata.attachmentUrl,
    leaveTypeId: metadata.leaveType?.id,
    leaveTypeCode: metadata.leaveType?.code,
    overtimeRuleId: metadata.overtimeRule?.id,
    overtimeRuleName: metadata.overtimeRule?.name,
  })
  return (
    rowFingerprint.requestedInAt === fingerprint.requestedInAt
    && rowFingerprint.requestedOutAt === fingerprint.requestedOutAt
    && rowFingerprint.reason === fingerprint.reason
    && rowFingerprint.minutes === fingerprint.minutes
    && rowFingerprint.attachmentUrl === fingerprint.attachmentUrl
    && rowFingerprint.leaveTypeId === fingerprint.leaveTypeId
    && rowFingerprint.leaveTypeCode === fingerprint.leaveTypeCode
    && rowFingerprint.overtimeRuleId === fingerprint.overtimeRuleId
    && rowFingerprint.overtimeRuleName === fingerprint.overtimeRuleName
  )
}

function normalizeStatusLabel(value) {
  if (value === null || value === undefined) return null
  const text = String(value).trim()
  if (!text) return null
  const normalized = text.toLowerCase()
  const map = {
    normal: 'normal',
    ok: 'normal',
    '正常': 'normal',
    late: 'late',
    '迟到': 'late',
    '早退': 'early_leave',
    early: 'early_leave',
    '迟到早退': 'late_early',
    'late+early': 'late_early',
    partial: 'partial',
    '缺卡': 'partial',
    '补卡': 'adjusted',
    adjusted: 'adjusted',
    absent: 'absent',
    '旷工': 'absent',
    off: 'off',
    '休息': 'off',
  }
  return map[text] ?? map[normalized] ?? normalized.replace(/\s+/g, '_')
}

function resolveStatusOverride(value, statusMap) {
  if (value === null || value === undefined) return null
  const text = String(value).trim()
  if (!text) return null
  if (statusMap && typeof statusMap === 'object') {
    const direct = statusMap[text] ?? statusMap[text.toLowerCase()]
    if (typeof direct === 'string' && direct.trim()) return direct.trim()
    const keys = Object.keys(statusMap)
    let bestMatch = null
    for (const key of keys) {
      if (!key) continue
      const lowerKey = String(key).toLowerCase()
      const lowerText = text.toLowerCase()
      if (lowerText.startsWith(lowerKey) || lowerText.includes(lowerKey)) {
        if (!bestMatch || key.length > bestMatch.length) bestMatch = key
      }
    }
    if (bestMatch && typeof statusMap[bestMatch] === 'string') {
      return String(statusMap[bestMatch]).trim()
    }
  }
  return normalizeStatusLabel(text)
}

function parseMinutesValue(value, dataType) {
  if (value === null || value === undefined || value === '') return null
  const numeric = parseNumber(value, null)
  if (!Number.isFinite(numeric)) return null
  const type = typeof dataType === 'string' ? dataType.toLowerCase() : ''
  if (type.includes('hour')) return Math.round(numeric * 60)
  if (type.includes('minute')) return Math.round(numeric)
  return Math.round(numeric)
}

function buildZonedDate(dateString, timeString, timeZone) {
  const dateParts = String(dateString).split('-').map(item => Number(item))
  if (dateParts.length !== 3 || dateParts.some(item => !Number.isFinite(item))) return null
  const [year, month, day] = dateParts
  const timeParts = String(timeString).split(':').map(item => Number(item))
  if (timeParts.length < 2 || timeParts.some(item => !Number.isFinite(item))) return null
  const [hour, minute, second] = [timeParts[0], timeParts[1], timeParts[2] ?? 0]
  const utcDate = new Date(Date.UTC(year, month - 1, day, hour, minute, second))
  if (!timeZone) return utcDate
  const tz = typeof timeZone === 'string' ? timeZone.trim() : ''
  if (!tz) return utcDate
  try {
    // Convert a local (zoned) wall-clock time into a UTC timestamp.
    const utcMs = zonedTimeToUtc({ year, month, day, hour, minute, second }, tz)
    return new Date(utcMs)
  } catch {
    return utcDate
  }
}

function parseImportedDateTime(value, workDate, timeZone) {
  if (!value) return null
  if (value instanceof Date) return value
  const text = String(value).trim()
  if (!text) return null
  const dateMatch = text.match(/\d{4}-\d{2}-\d{2}/)
  const timeMatch = text.match(/\d{2}:\d{2}(:\d{2})?/)
  if (dateMatch && timeMatch) {
    return buildZonedDate(dateMatch[0], timeMatch[0], timeZone)
  }
  if (timeMatch && workDate) {
    return buildZonedDate(workDate, timeMatch[0], timeZone)
  }
  return parseDateInput(text)
}

function normalizeTimeString(value) {
  if (!value || typeof value !== 'string') return null
  const match = value.trim().match(/^(\d{1,2}):(\d{2})(?::\d{2})?$/)
  if (!match) return null
  const hours = Number(match[1])
  const minutes = Number(match[2])
  if (!Number.isFinite(hours) || !Number.isFinite(minutes)) return null
  if (hours < 0 || hours > 23 || minutes < 0 || minutes > 59) return null
  const hh = String(hours).padStart(2, '0')
  const mm = String(minutes).padStart(2, '0')
  return `${hh}:${mm}`
}

function addDaysToDateKey(dateKey, days) {
  const normalized = normalizeDateOnly(dateKey)
  if (!normalized) return null
  const date = new Date(`${normalized}T00:00:00Z`)
  if (Number.isNaN(date.getTime())) return null
  date.setUTCDate(date.getUTCDate() + Number(days || 0))
  return date.toISOString().slice(0, 10)
}

// 排班修改窗 (schedule-edit window): pure evaluator. Given the org shiftEditPolicy, the dates a
// write touches, and today's date-key, returns a violation when the EARLIEST touched date falls
// before the editable boundary — so editing / creating / deleting a past-dated assignment is
// blocked uniformly (guard the write, not the verb). Unset / unrestricted / unknown mode => null
// (no regression). Org-level for v1; per-rule_set granularity is a follow-up.
function evaluateShiftEditWindow(policy, dates, todayKey) {
  const mode = policy && typeof policy === 'object' ? policy.mode : undefined
  if (!mode || mode === 'unrestricted') return null
  const today = normalizeDateOnly(todayKey)
  if (!today) return null
  const affected = (Array.isArray(dates) ? dates : [dates])
    .map((value) => normalizeDateOnly(value))
    .filter(Boolean)
  if (affected.length === 0) return null
  const earliest = affected.reduce((min, value) => (value < min ? value : min))
  let boundary
  if (mode === 'past_locked') {
    boundary = today
  } else if (mode === 'past_within_window') {
    const windowDays = Math.max(0, Math.floor(parseNumber(policy.windowDays, 0)))
    boundary = addDaysToDateKey(today, -windowDays) ?? today
  } else {
    return null
  }
  return earliest < boundary ? { earliest, boundary, mode } : null
}

function inferOvernightFlag(workStartTime, workEndTime) {
  const normalizedStart = normalizeTimeString(workStartTime)
  const normalizedEnd = normalizeTimeString(workEndTime)
  if (!normalizedStart || !normalizedEnd || normalizedStart === normalizedEnd) return false
  return parseTimeToMinutes(normalizedStart, 0) > parseTimeToMinutes(normalizedEnd, 0)
}

function resolveOvernightFlag(explicitValue, workStartTime, workEndTime) {
  if (typeof explicitValue === 'boolean') return explicitValue
  return inferOvernightFlag(workStartTime, workEndTime)
}

function resolveShiftTiming({ workStartTime: rawWorkStartTime, workEndTime: rawWorkEndTime, explicitOvernight, fallbackOvernight }) {
  const workStartTime = normalizeTimeString(rawWorkStartTime)
  const workEndTime = normalizeTimeString(rawWorkEndTime)
  if (!workStartTime || !workEndTime) {
    return { error: 'Shift times must use HH:MM format' }
  }
  const inferredOvernight = inferOvernightFlag(workStartTime, workEndTime)
  if (explicitOvernight === false && inferredOvernight) {
    return { error: 'Set isOvernight=true when shift end is earlier than shift start' }
  }
  if (explicitOvernight === true && !inferredOvernight) {
    return { error: 'Overnight shifts must end after midnight' }
  }
  return {
    workStartTime,
    workEndTime,
    isOvernight: resolveOvernightFlag(firstDefinedValue(explicitOvernight, fallbackOvernight), workStartTime, workEndTime),
  }
}

function resolveShiftTimeRange(shiftName) {
  if (!shiftName) return null
  const text = String(shiftName)
  const match = text.match(/(\d{1,2}:\d{2})\s*[-~—]\s*(\d{1,2}:\d{2})/)
  if (!match) return null
  const workStartTime = normalizeTimeString(match[1])
  const workEndTime = normalizeTimeString(match[2])
  if (!workStartTime || !workEndTime) return null
  return { workStartTime, workEndTime }
}

function resolveRuleOverrideFromShiftName(rule, shiftName) {
  const range = resolveShiftTimeRange(shiftName)
  if (!range) return rule
  return { ...rule, ...range }
}

function buildDingTalkFieldMap(columns) {
  const map = new Map()
  if (!Array.isArray(columns)) return map
  for (const column of columns) {
    const id = column?.id ?? column?.column_id ?? column?.columnId
    if (id === undefined || id === null) continue
    const key = String(id)
    const alias = typeof column.alias === 'string' && column.alias.trim().length > 0 ? column.alias.trim() : null
    const name = typeof column.name === 'string' && column.name.trim().length > 0 ? column.name.trim() : null
    map.set(key, { id: key, alias, name })
  }
  return map
}

function buildRowsFromDingTalk({ columns, data, userId }) {
  const map = buildDingTalkFieldMap(columns)
  const rowsByDate = new Map()
  const resolvedUserId = data?.userId ?? data?.userid ?? userId ?? null
  const columnVals = data?.column_vals
  if (!Array.isArray(columnVals)) return []
  for (const columnEntry of columnVals) {
    const colId = columnEntry?.column_vo?.id ?? columnEntry?.column_vo?.column_id ?? columnEntry?.columnId
    if (colId === undefined || colId === null) continue
    const columnInfo = map.get(String(colId)) ?? { id: String(colId) }
    const keys = []
    if (columnInfo.alias) keys.push(columnInfo.alias)
    if (columnInfo.name) keys.push(columnInfo.name)
    keys.push(`col_${columnInfo.id}`)
    const values = Array.isArray(columnEntry?.column_vals) ? columnEntry.column_vals : []
    for (const entry of values) {
      const dateRaw = entry?.date
      if (!dateRaw) continue
      const dateKey = String(dateRaw).slice(0, 10)
      if (!rowsByDate.has(dateKey)) {
        rowsByDate.set(dateKey, {
          workDate: dateKey,
          fields: {},
          userId: resolvedUserId ?? undefined,
        })
      }
      const row = rowsByDate.get(dateKey)
      const rawValue = entry?.value ?? entry?.date ?? ''
      for (const key of keys) {
        if (key && row.fields[key] === undefined) {
          row.fields[key] = rawValue
        }
      }
    }
  }
  return Array.from(rowsByDate.values())
}

function buildRowsFromEntries({ entries }) {
  if (!Array.isArray(entries)) return []
  const rowsByKey = new Map()
  for (const entry of entries) {
    const meta = entry?.meta ?? {}
    const workDate = entry?.workDate ?? meta.workDate ?? (entry?.occurredAt ? String(entry.occurredAt).slice(0, 10) : null)
    if (!workDate) continue
    const userId = entry?.userId ?? meta.userId
    const rowKey = `${userId ?? meta.sourceUserKey ?? 'unknown'}|${workDate}`
    if (!rowsByKey.has(rowKey)) {
      rowsByKey.set(rowKey, { workDate, fields: {}, userId })
    }
    const row = rowsByKey.get(rowKey)
    if (!row.userId && userId) row.userId = userId
    const column = meta.column ?? entry?.column ?? entry?.field
    const rawValue = meta.rawTime ?? meta.value ?? entry?.value ?? entry?.occurredAt ?? ''
    if (column && row.fields[column] === undefined) {
      row.fields[column] = rawValue
    }
    if (meta.sourceUserKey && row.fields.sourceUserKey === undefined) {
      row.fields.sourceUserKey = meta.sourceUserKey
    }
    if (meta.sourceUserName && row.fields.sourceUserName === undefined) {
      row.fields.sourceUserName = meta.sourceUserName
    }
    if (meta.sourceUserKey && row.fields.empNo === undefined) {
      row.fields.empNo = meta.sourceUserKey
    }
    if (entry?.eventType && row.fields.eventType === undefined) {
      row.fields.eventType = entry.eventType
    }
  }
  return Array.from(rowsByKey.values())
}

function resolvePositiveIntEnv(name, fallback, { min = 1, max = Number.MAX_SAFE_INTEGER } = {}) {
  const raw = Number(process.env[name] ?? fallback)
  if (!Number.isFinite(raw)) return fallback
  const parsed = Math.floor(raw)
  if (!Number.isFinite(parsed)) return fallback
  return Math.min(max, Math.max(min, parsed))
}

