function iterateCsvRows(csvText, delimiter = ',', onRow) {
  if (typeof csvText !== 'string' || !csvText.trim()) return { rowCount: 0, stoppedEarly: false }
  const sep = typeof delimiter === 'string' && delimiter.length > 0 ? delimiter[0] : ','
  let row = []
  let field = ''
  let inQuotes = false
  let rowCount = 0
  let stoppedEarly = false

  const emitRow = () => {
    row.push(field)
    field = ''
    const keepRow = row.length > 1 || row[0]?.trim()
    if (!keepRow) {
      row = []
      return true
    }
    const shouldContinue = typeof onRow === 'function' ? onRow(row, rowCount) !== false : true
    rowCount += 1
    row = []
    if (!shouldContinue) {
      stoppedEarly = true
      return false
    }
    return true
  }

  for (let i = 0; i < csvText.length; i += 1) {
    const ch = csvText[i]
    if (inQuotes) {
      if (ch === '"') {
        const next = csvText[i + 1]
        if (next === '"') {
          field += '"'
          i += 1
        } else {
          inQuotes = false
        }
      } else if (ch === '\r') {
        if (csvText[i + 1] === '\n') i += 1
        field += '\n'
      } else {
        field += ch
      }
      continue
    }

    if (ch === '"') {
      inQuotes = true
      continue
    }
    if (ch === sep) {
      row.push(field)
      field = ''
      continue
    }
    if (ch === '\n' || ch === '\r') {
      if (ch === '\r' && csvText[i + 1] === '\n') i += 1
      if (!emitRow()) break
      continue
    }
    field += ch
  }

  if (!stoppedEarly) {
    emitRow()
  }

  return { rowCount, stoppedEarly }
}

async function iterateCsvRowsAsync(csvText, delimiter = ',', onRow) {
  if (typeof csvText !== 'string' || !csvText.trim()) return { rowCount: 0, stoppedEarly: false }
  const sep = typeof delimiter === 'string' && delimiter.length > 0 ? delimiter[0] : ','
  let row = []
  let field = ''
  let inQuotes = false
  let rowCount = 0
  let stoppedEarly = false

  const emitRow = async () => {
    row.push(field)
    field = ''
    const keepRow = row.length > 1 || row[0]?.trim()
    if (!keepRow) {
      row = []
      return true
    }
    const shouldContinue = typeof onRow === 'function'
      ? await onRow(row, rowCount) !== false
      : true
    rowCount += 1
    row = []
    if (!shouldContinue) {
      stoppedEarly = true
      return false
    }
    return true
  }

  for (let i = 0; i < csvText.length; i += 1) {
    const ch = csvText[i]
    if (inQuotes) {
      if (ch === '"') {
        const next = csvText[i + 1]
        if (next === '"') {
          field += '"'
          i += 1
        } else {
          inQuotes = false
        }
      } else if (ch === '\r') {
        if (csvText[i + 1] === '\n') i += 1
        field += '\n'
      } else {
        field += ch
      }
      continue
    }

    if (ch === '"') {
      inQuotes = true
      continue
    }
    if (ch === sep) {
      row.push(field)
      field = ''
      continue
    }
    if (ch === '\n' || ch === '\r') {
      if (ch === '\r' && csvText[i + 1] === '\n') i += 1
      if (!await emitRow()) break
      continue
    }
    field += ch
  }

  if (!stoppedEarly) {
    await emitRow()
  }

  return { rowCount, stoppedEarly }
}

async function iterateCsvRowsStreamAsync(readable, delimiter = ',', onRow) {
  if (!readable || typeof readable[Symbol.asyncIterator] !== 'function') {
    return { rowCount: 0, stoppedEarly: false }
  }
  const sep = typeof delimiter === 'string' && delimiter.length > 0 ? delimiter[0] : ','
  const decoder = new StringDecoder('utf8')
  let row = []
  let field = ''
  let inQuotes = false
  let rowCount = 0
  let stoppedEarly = false

  const emitRow = async () => {
    row.push(field)
    field = ''
    const keepRow = row.length > 1 || row[0]?.trim()
    if (!keepRow) {
      row = []
      return true
    }
    const shouldContinue = typeof onRow === 'function'
      ? await onRow(row, rowCount) !== false
      : true
    rowCount += 1
    row = []
    if (!shouldContinue) {
      stoppedEarly = true
      return false
    }
    return true
  }

  const processChunk = async (text) => {
    for (let i = 0; i < text.length; i += 1) {
      const ch = text[i]
      if (inQuotes) {
        if (ch === '"') {
          const next = text[i + 1]
          if (next === '"') {
            field += '"'
            i += 1
          } else {
            inQuotes = false
          }
        } else if (ch === '\r') {
          if (text[i + 1] === '\n') i += 1
          field += '\n'
        } else {
          field += ch
        }
        continue
      }

      if (ch === '"') {
        inQuotes = true
        continue
      }
      if (ch === sep) {
        row.push(field)
        field = ''
        continue
      }
      if (ch === '\n' || ch === '\r') {
        if (ch === '\r' && text[i + 1] === '\n') i += 1
        if (!await emitRow()) return false
        continue
      }
      field += ch
    }
    return true
  }

  for await (const chunk of readable) {
    const text = typeof chunk === 'string' ? chunk : decoder.write(chunk)
    if (!text) continue
    if (!await processChunk(text)) break
  }

  if (!stoppedEarly) {
    const tail = decoder.end()
    if (tail) {
      await processChunk(tail)
    }
  } else {
    decoder.end()
  }

  if (!stoppedEarly) {
    await emitRow()
  }

  return { rowCount, stoppedEarly }
}

function normalizeCsvHeaderValue(value) {
  if (value === undefined || value === null) return ''
  const text = String(value).replace(/\ufeff/g, '').trim()
  return text
}

function detectCsvHeaderIndex(csvText, delimiter) {
  let detectedIndex = 0
  let found = false
  iterateCsvRows(csvText, delimiter, (rawRow, rowIndex) => {
    const row = rawRow.map(normalizeCsvHeaderValue).filter(Boolean)
    if (!row.length) return true
    const hasName = row.some((cell) => cell === '姓名' || cell.toLowerCase() === 'name')
    const hasDate = row.some((cell) => ['日期', 'date', 'workdate', 'work_date'].includes(cell.toLowerCase()))
    if (hasName && hasDate) {
      detectedIndex = rowIndex
      found = true
      return false
    }
    return true
  })
  return found ? detectedIndex : 0
}

function normalizeCsvWorkDate(value) {
  if (value === undefined || value === null) return null
  const text = String(value).trim()
  if (!text) return null
  const numeric = text.replace(/[^0-9]/g, '')
  if (/^\d{13}$/.test(numeric)) {
    const date = new Date(Number(numeric))
    return Number.isNaN(date.getTime()) ? null : date.toISOString().slice(0, 10)
  }
  if (/^\d{10}$/.test(numeric)) {
    const date = new Date(Number(numeric) * 1000)
    return Number.isNaN(date.getTime()) ? null : date.toISOString().slice(0, 10)
  }
  const cleaned = text.split(' ')[0].trim()
  if (/^\d{4}-\d{2}-\d{2}$/.test(cleaned)) return cleaned
  if (/^\d{2}-\d{2}-\d{2}$/.test(cleaned)) {
    const [yy, mm, dd] = cleaned.split('-')
    return `20${yy}-${mm}-${dd}`
  }
  if (/^\d{4}[/-]\d{1,2}[/-]\d{1,2}$/.test(cleaned)) {
    const [yyyy, mm, dd] = cleaned.split(/[/-]/)
    return `${yyyy}-${String(mm).padStart(2, '0')}-${String(dd).padStart(2, '0')}`
  }
  return null
}

function isRestShiftRow(row) {
  const fields = row?.fields || {}
  const candidates = [
    fields.shiftName,
    fields.plan_detail,
    fields.attendanceClass,
    fields.attendance_class,
    fields['班次'],
    fields['出勤班次'],
    fields.status,
    fields.attend_result,
    fields['考勤结果'],
    fields['当天考勤情况'],
  ]
  return candidates.some((value) => {
    if (value === undefined || value === null) return false
    return String(value).includes('休息')
  })
}

