    context.api.http.addRoute(
      'GET',
      '/api/attendance/advanced-scheduling/workbench',
      withPermission('attendance:admin', async (req, res) => {
        const fromRaw = typeof req.query.from === 'string' ? req.query.from.trim() : ''
        const toRaw = typeof req.query.to === 'string' ? req.query.to.trim() : ''
        const from = fromRaw ? normalizeDateOnlyStrict(fromRaw) : null
        const to = toRaw ? normalizeDateOnlyStrict(toRaw) : null
        if (fromRaw && !from) {
          res.status(400).json({ ok: false, error: { code: 'VALIDATION_ERROR', message: 'Invalid "from" date. Use YYYY-MM-DD.' } })
          return
        }
        if (toRaw && !to) {
          res.status(400).json({ ok: false, error: { code: 'VALIDATION_ERROR', message: 'Invalid "to" date. Use YYYY-MM-DD.' } })
          return
        }
        if (from && to && from > to) {
          res.status(400).json({ ok: false, error: { code: 'VALIDATION_ERROR', message: '"from" must be on or before "to".' } })
          return
        }
        const orgId = getOrgId(req)
        const rangeStart = from ?? '0001-01-01'
        const rangeEnd = to ?? ATTENDANCE_SCHEDULE_OPEN_END_DATE

        try {
          const [
            scheduleGroupRows,
            scheduleGroupMemberRows,
            schedulerScopeRows,
            shiftRows,
            rotationRuleRows,
            shiftAssignmentRows,
            rotationAssignmentRows,
            assignmentAggregateRows,
            scheduleGroupAssignmentAggregateRows,
            ruleSetAttendanceGroupIds,
          ] = await Promise.all([
            db.query(
              `SELECT *
               FROM attendance_schedule_groups
               WHERE org_id = $1 AND is_active = true
               ORDER BY name ASC, created_at DESC`,
              [orgId]
            ),
            db.query(
              `SELECT *
               FROM attendance_schedule_group_members
               WHERE org_id = $1
                 AND COALESCE(effective_from, DATE '0001-01-01') <= $3::date
                 AND COALESCE(effective_to, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ORDER BY schedule_group_id ASC, effective_from ASC NULLS FIRST, user_id ASC`,
              [orgId, rangeStart, rangeEnd]
            ),
            db.query(
              `SELECT *
               FROM attendance_scheduler_scopes
               WHERE org_id = $1 AND is_active = true
               ORDER BY subject_type ASC, subject_ref ASC, created_at DESC`,
              [orgId]
            ),
            db.query(
              `SELECT *
               FROM attendance_shifts
               WHERE org_id = $1
               ORDER BY name ASC, created_at DESC`,
              [orgId]
            ),
            db.query(
              `SELECT *
               FROM attendance_rotation_rules
               WHERE org_id = $1
               ORDER BY is_active DESC, name ASC, created_at DESC`,
              [orgId]
            ),
            db.query(
              `SELECT a.id, a.org_id, a.user_id, a.shift_id, a.start_date, a.end_date, a.is_active,
                      a.publish_status, a.publish_batch_id, a.publish_requested_at, a.publish_requested_by,
                      a.published_at, a.published_by, a.locked_at, a.reopened_from_assignment_id,
                      s.name AS shift_name, s.timezone AS shift_timezone, s.work_start_time AS shift_work_start_time,
                      s.work_end_time AS shift_work_end_time, s.is_overnight AS shift_is_overnight,
                      s.late_grace_minutes AS shift_late_grace_minutes,
                      s.early_grace_minutes AS shift_early_grace_minutes,
                      s.rounding_minutes AS shift_rounding_minutes,
                      s.working_days AS shift_working_days
               FROM attendance_shift_assignments a
               JOIN attendance_shifts s ON s.id = a.shift_id
               WHERE a.org_id = $1
                 AND COALESCE(a.is_active, true) = true
                 AND COALESCE(a.publish_status, 'published') = 'published'
                 AND a.start_date <= $3::date
                 AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ORDER BY a.start_date DESC, a.created_at DESC
               LIMIT ${ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT + 1}`,
              [orgId, rangeStart, rangeEnd]
            ),
            db.query(
              `SELECT a.id, a.org_id, a.user_id, a.rotation_rule_id, a.start_date, a.end_date, a.is_active,
                      a.publish_status, a.publish_batch_id, a.publish_requested_at, a.publish_requested_by,
                      a.published_at, a.published_by, a.locked_at, a.reopened_from_assignment_id,
                      r.name AS rotation_name, r.timezone AS rotation_timezone,
                      r.shift_sequence AS rotation_shift_sequence,
                      r.is_active AS rotation_is_active
               FROM attendance_rotation_assignments a
               JOIN attendance_rotation_rules r ON r.id = a.rotation_rule_id
               WHERE a.org_id = $1
                 AND COALESCE(a.is_active, true) = true
                 AND COALESCE(a.publish_status, 'published') = 'published'
                 AND a.start_date <= $3::date
                 AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ORDER BY a.start_date DESC, a.created_at DESC
               LIMIT ${ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT + 1}`,
              [orgId, rangeStart, rangeEnd]
            ),
            db.query(
              `WITH active_shift AS (
                 SELECT a.id, a.user_id
                 FROM attendance_shift_assignments a
                 JOIN attendance_shifts s ON s.id = a.shift_id
                 WHERE a.org_id = $1
                   AND COALESCE(a.is_active, true) = true
                   AND COALESCE(a.publish_status, 'published') = 'published'
                   AND a.start_date <= $3::date
                   AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ),
               active_rotation AS (
                 SELECT a.id, a.user_id
                 FROM attendance_rotation_assignments a
                 JOIN attendance_rotation_rules r ON r.id = a.rotation_rule_id
                 WHERE a.org_id = $1
                   AND COALESCE(a.is_active, true) = true
                   AND COALESCE(a.publish_status, 'published') = 'published'
                   AND a.start_date <= $3::date
                   AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ),
               assigned_users AS (
                 SELECT user_id FROM active_shift WHERE user_id IS NOT NULL
                 UNION
                 SELECT user_id FROM active_rotation WHERE user_id IS NOT NULL
               ),
               active_members AS (
                 SELECT DISTINCT user_id
                 FROM attendance_schedule_group_members
                 WHERE org_id = $1
                   AND user_id IS NOT NULL
                   AND COALESCE(effective_from, DATE '0001-01-01') <= $3::date
                   AND COALESCE(effective_to, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ),
               mixed_users AS (
                 SELECT s.user_id
                 FROM active_shift s
                 JOIN active_rotation r ON r.user_id = s.user_id
                 WHERE s.user_id IS NOT NULL
                 GROUP BY s.user_id
               )
               SELECT
                 (SELECT COUNT(*) FROM active_shift)::int AS shift_assignments,
                 (SELECT COUNT(*) FROM active_rotation)::int AS rotation_assignments,
                 (SELECT COUNT(*) FROM assigned_users)::int AS assigned_users,
                 (SELECT COUNT(*) FROM assigned_users au WHERE NOT EXISTS (
                   SELECT 1 FROM active_members m WHERE m.user_id = au.user_id
                 ))::int AS assignment_users_without_schedule_group,
                 (SELECT COUNT(*) FROM mixed_users)::int AS users_with_both_assignment_kinds`,
              [orgId, rangeStart, rangeEnd]
            ),
            db.query(
              `WITH active_members AS (
                 SELECT schedule_group_id, user_id
                 FROM attendance_schedule_group_members
                 WHERE org_id = $1
                   AND user_id IS NOT NULL
                   AND schedule_group_id IS NOT NULL
                   AND COALESCE(effective_from, DATE '0001-01-01') <= $3::date
                   AND COALESCE(effective_to, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
               ),
               shift_counts AS (
                 SELECT a.user_id, COUNT(*)::int AS assignment_count
                 FROM attendance_shift_assignments a
                 JOIN attendance_shifts s ON s.id = a.shift_id
                 WHERE a.org_id = $1
                   AND COALESCE(a.is_active, true) = true
                   AND COALESCE(a.publish_status, 'published') = 'published'
                   AND a.start_date <= $3::date
                   AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
                 GROUP BY a.user_id
               ),
               rotation_counts AS (
                 SELECT a.user_id, COUNT(*)::int AS assignment_count
                 FROM attendance_rotation_assignments a
                 JOIN attendance_rotation_rules r ON r.id = a.rotation_rule_id
                 WHERE a.org_id = $1
                   AND COALESCE(a.is_active, true) = true
                   AND COALESCE(a.publish_status, 'published') = 'published'
                   AND a.start_date <= $3::date
                   AND COALESCE(a.end_date, DATE '${ATTENDANCE_SCHEDULE_OPEN_END_DATE}') >= $2::date
                 GROUP BY a.user_id
               )
               SELECT
                 m.schedule_group_id,
                 COUNT(DISTINCT CASE
                   WHEN COALESCE(s.assignment_count, 0) + COALESCE(r.assignment_count, 0) > 0 THEN m.user_id
                   ELSE NULL
                 END)::int AS assigned_user_count,
                 COALESCE(SUM(COALESCE(s.assignment_count, 0)), 0)::int AS shift_assignment_count,
                 COALESCE(SUM(COALESCE(r.assignment_count, 0)), 0)::int AS rotation_assignment_count
               FROM active_members m
               LEFT JOIN shift_counts s ON s.user_id = m.user_id
               LEFT JOIN rotation_counts r ON r.user_id = m.user_id
               GROUP BY m.schedule_group_id`,
              [orgId, rangeStart, rangeEnd]
            ),
            // Optional visibility signal — schema-safe: degrades to [] (diagnostic absent)
            // if attendance_groups.rule_set_id is missing, instead of failing the workbench.
            loadAttendanceRuleSetAttendanceGroupIds(db, orgId),
          ])

          const shiftAssignmentsTruncated = shiftAssignmentRows.length > ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT
          const rotationAssignmentsTruncated = rotationAssignmentRows.length > ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT
          const visibleShiftAssignmentRows = shiftAssignmentRows.slice(0, ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT)
          const visibleRotationAssignmentRows = rotationAssignmentRows.slice(0, ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT)

          const data = buildAttendanceAdvancedSchedulingWorkbench({
            from,
            to,
            scheduleGroups: scheduleGroupRows.map(mapAttendanceScheduleGroupRow),
            scheduleGroupMembers: scheduleGroupMemberRows.map(mapAttendanceScheduleGroupMemberRow),
            schedulerScopes: schedulerScopeRows.map(mapAttendanceSchedulerScopeRow),
            shifts: shiftRows.map(mapShiftRow),
            rotationRules: rotationRuleRows.map(mapRotationRuleRow),
            shiftAssignments: visibleShiftAssignmentRows.map(row => ({
              assignment: mapAssignmentRow(row),
              shift: mapShiftFromAssignmentRow(row),
            })),
            rotationAssignments: visibleRotationAssignmentRows.map(row => ({
              assignment: mapRotationAssignmentRow(row),
              rotation: mapRotationRuleFromAssignmentRow(row),
            })),
            assignmentAggregates: {
              shiftAssignments: assignmentAggregateRows[0]?.shift_assignments,
              rotationAssignments: assignmentAggregateRows[0]?.rotation_assignments,
              assignedUsers: assignmentAggregateRows[0]?.assigned_users,
              assignmentUsersWithoutScheduleGroup: assignmentAggregateRows[0]?.assignment_users_without_schedule_group,
              usersWithBothAssignmentKinds: assignmentAggregateRows[0]?.users_with_both_assignment_kinds,
            },
            scheduleGroupAssignmentAggregates: scheduleGroupAssignmentAggregateRows.map(row => ({
              scheduleGroupId: row.schedule_group_id,
              assignedUserCount: row.assigned_user_count,
              shiftAssignmentCount: row.shift_assignment_count,
              rotationAssignmentCount: row.rotation_assignment_count,
            })),
            assignmentLimit: ATTENDANCE_ADVANCED_SCHEDULING_WORKBENCH_ASSIGNMENT_LIMIT,
            shiftAssignmentsTruncated,
            rotationAssignmentsTruncated,
            ruleSetAttendanceGroupIds,
          })
          res.json({ ok: true, data })
        } catch (error) {
          if (isDatabaseSchemaError(error)) {
            res.status(503).json({ ok: false, error: { code: 'DB_NOT_READY', message: 'Attendance scheduling tables missing' } })
            return
          }
          logger.error('Attendance advanced scheduling workbench query failed', error)
          res.status(500).json({ ok: false, error: { code: 'INTERNAL_ERROR', message: 'Failed to load advanced scheduling workbench' } })
        }
      })
    )

